import type { Article, LawSection } from '../../../common/types/law.types';

export const SECTION_03: LawSection = { id: 'ccyc-s03', lawId: 'codigo-civil-comercial', number: 'III', name: 'Libro Primero - Parte General (Arts. 281-400)', articleStart: 281, articleEnd: 400, titles: [] };

export const ARTICLES_03: Article[] = [
  { id: 'ccyc-art-281', lawId: 'codigo-civil-comercial', number: '281', order: 281, title: "Causa", text: "Causa. La causa es el fin inmediato autorizado por el ordenamiento jurídico que ha sido determinante de la voluntad. También integran la causa los motivos exteriorizados cuando sean lícitos y hayan sido incorporados al acto en forma expresa, o tácitamente si son esenciales para ambas partes.", plainLanguageExplanation: "Establece el régimen de causa. La causa es el fin inmediato autorizado por el ordenamiento jurídico que ha sido determinante de la voluntad.", practicalEffects: ['En la práctica, este artículo rige causa. La causa es el fin inmediato autorizado por el ordenamiento jurídico que ha sido determinante de la voluntad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['causaarticulo 281'], segments: [], amendments: [] },
  { id: 'ccyc-art-282', lawId: 'codigo-civil-comercial', number: '282', order: 282, title: "Presunción de causa", text: "Presunción de causa. Aunque la causa no esté expresada en el acto se presume que existe mientras no se pruebe lo contrario. El acto es válido aunque la causa expresada sea falsa si se funda en otra causa verdadera.", plainLanguageExplanation: "Establece el régimen de presunción de causa. Aunque la causa no esté expresada en el acto se presume que existe mientras no se pruebe lo contrario.", practicalEffects: ['En la práctica, este artículo rige presunción de causa. Aunque la causa no esté expresada en el acto se presume que existe mientras no se pruebe lo contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presuncin', 'causa', 'articulo 282'], segments: [], amendments: [] },
  { id: 'ccyc-art-283', lawId: 'codigo-civil-comercial', number: '283', order: 283, title: "Acto abstracto", text: "Acto abstracto. La inexistencia, falsedad o ilicitud de la causa no son discutibles en el acto abstracto mientras no se haya cumplido, excepto que la ley lo autorice. SECCION 3ª Forma y prueba del acto jurídico", plainLanguageExplanation: "Establece el régimen de acto abstracto. La inexistencia, falsedad o ilicitud de la causa no son discutibles en el acto abstracto mientras no se haya cumplido, excepto que la ley lo autorice.", practicalEffects: ['En la práctica, este artículo rige acto abstracto. La inexistencia, falsedad o ilicitud de la causa no son discutibles en el acto abstracto mientras no se haya cumplido, excepto que la ley lo autorice.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acto', 'abstracto', 'articulo 283'], segments: [], amendments: [] },
  { id: 'ccyc-art-284', lawId: 'codigo-civil-comercial', number: '284', order: 284, title: "Libertad de formas", text: "Libertad de formas. Si la ley no designa una forma determinada para la exteriorización de la voluntad, las partes pueden utilizar la que estimen conveniente. Las partes pueden convenir una forma más exigente que la impuesta por la ley.", plainLanguageExplanation: "Establece el régimen de libertad de formas. Si la ley no designa una forma determinada para la exteriorización de la voluntad, las partes pueden utilizar la que estimen conveniente.", practicalEffects: ['En la práctica, este artículo rige libertad de formas. Si la ley no designa una forma determinada para la exteriorización de la voluntad, las partes pueden utilizar la que estimen conveniente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad', 'formas', 'articulo 284'], segments: [], amendments: [] },
  { id: 'ccyc-art-285', lawId: 'codigo-civil-comercial', number: '285', order: 285, title: "Forma impuesta", text: "Forma impuesta. El acto que no se otorga en la forma exigida por la ley no queda concluido como tal mientras no se haya otorgado el instrumento previsto, pero vale como acto en el que las partes se han obligado a cumplir con la expresada formalidad, excepto que ella se exija bajo sanción de nulidad.", plainLanguageExplanation: "Establece el régimen de forma impuesta. El acto que no se otorga en la forma exigida por la ley no queda concluido como tal mientras no se haya otorgado el instrumento previsto, pero vale como acto en el que las partes se han obligado a cumplir con la expresada formalidad, excepto que ella se exija bajo sanción de nuli", practicalEffects: ['En la práctica, este artículo rige forma impuesta. El acto que no se otorga en la forma exigida por la ley no queda concluido como tal mientras no se haya otorgado el instrumento previsto, pero vale co'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma', 'impuesta', 'articulo 285'], segments: [], amendments: [] },
  { id: 'ccyc-art-286', lawId: 'codigo-civil-comercial', number: '286', order: 286, title: "Expresión escrita", text: "Expresión escrita. La expresión escrita puede tener lugar por instrumentos públicos, o por instrumentos particulares firmados o no firmados, excepto en los casos en que determinada instrumentación sea impuesta. Puede hacerse constar en cualquier soporte, siempre que su contenido sea representado con texto inteligible, aunque su lectura exija medios técnicos.", plainLanguageExplanation: "Establece el régimen de expresión escrita. La expresión escrita puede tener lugar por instrumentos públicos, o por instrumentos particulares firmados o no firmados, excepto en los casos en que determinada instrumentación sea impuesta.", practicalEffects: ['En la práctica, este artículo rige expresión escrita. La expresión escrita puede tener lugar por instrumentos públicos, o por instrumentos particulares firmados o no firmados, excepto en los casos en que determinada instrumentación sea impuesta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['expresin', 'escrita', 'articulo 286'], segments: [], amendments: [] },
  { id: 'ccyc-art-287', lawId: 'codigo-civil-comercial', number: '287', order: 287, title: "Instrumentos privados y particulares no firmados", text: "Instrumentos privados y particulares no firmados. Los instrumentos particulares pueden estar firmados o no. Si lo están, se llaman instrumentos privados. Si no lo están, se los denomina instrumentos particulares no firmados; esta categoría comprende todo escrito no firmado, entre otros, los impresos, los registros visuales o auditivos de cosas o hechos y, cualquiera que sea el medio empleado, los registros de la palabra y de información.", plainLanguageExplanation: "Establece el régimen de instrumentos privados y particulares no firmados. Los instrumentos particulares pueden estar firmados o no.", practicalEffects: ['En la práctica, este artículo rige instrumentos privados y particulares no firmados. Los instrumentos particulares pueden estar firmados o no.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['instrumentos', 'privados', 'particulares', 'firmados', 'articulo 287'], segments: [], amendments: [] },
  { id: 'ccyc-art-288', lawId: 'codigo-civil-comercial', number: '288', order: 288, title: "Firma", text: "Firma. La firma prueba la autoría de la declaración de voluntad expresada en el texto al cual corresponde. Debe consistir en el nombre del firmante o en un signo. En los instrumentos generados por medios electrónicos, el requisito de la firma de una persona queda satisfecho si se utiliza una firma digital, que asegure indubitablemente la autoría e integridad del instrumento. SECCION 4ª Instrumentos públicos", plainLanguageExplanation: "Establece el régimen de firma. La firma prueba la autoría de la declaración de voluntad expresada en el texto al cual corresponde.", practicalEffects: ['En la práctica, este artículo rige firma. La firma prueba la autoría de la declaración de voluntad expresada en el texto al cual corresponde.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['firmaarticulo 288'], segments: [], amendments: [] },
  { id: 'ccyc-art-289', lawId: 'codigo-civil-comercial', number: '289', order: 289, title: "Enunciación", text: "Enunciación. Son instrumentos públicos: a) las escrituras públicas y sus copias o testimonios; b) los instrumentos que extienden los escribanos o los funcionarios públicos con los requisitos que establecen las leyes; c) los títulos emitidos por el Estado nacional, provincial o la Ciudad Autónoma de Buenos Aires, conforme a las leyes que autorizan su emisión.", plainLanguageExplanation: "Establece el régimen de enunciación. Son instrumentos públicos: a) las escrituras públicas y sus copias o testimonios; b) los instrumentos que extienden los escribanos o los funcionarios públicos con los requisitos que establecen las leyes; c) los títulos emitidos por el Estado nacional, provincial o la Ciudad Autón", practicalEffects: ['En la práctica, este artículo rige enunciación. Son instrumentos públicos: a) las escrituras públicas y sus copias o testimonios; b) los instrumentos que extienden los escribanos o los funcionarios'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['enunciacinarticulo 289'], segments: [], amendments: [] },
  { id: 'ccyc-art-290', lawId: 'codigo-civil-comercial', number: '290', order: 290, title: "Requisitos del instrumento público", text: "Requisitos del instrumento público. Son requisitos de validez del instrumento público: a) la actuación del oficial público en los límites de sus atribuciones y de su competencia territorial, excepto que el lugar sea generalmente tenido como comprendido en ella; b) las firmas del oficial público, de las partes, y en su caso, de sus representantes; si alguno de ellos no firma por sí mismo o a ruego, el instrumento carece de validez para todos.", plainLanguageExplanation: "Establece el régimen de requisitos del instrumento público. Son requisitos de validez del instrumento público: a) la actuación del oficial público en los límites de sus atribuciones y de su competencia territorial, excepto que el lugar sea generalmente tenido como comprendido en ella; b) las firmas del oficial público, de las partes, y en", practicalEffects: ['En la práctica, este artículo rige requisitos del instrumento público. Son requisitos de validez del instrumento público: a) la actuación del oficial público en los límites de sus atribuciones y de su competencia territor'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos', 'instrumento', 'pblico', 'articulo 290'], segments: [], amendments: [] },
  { id: 'ccyc-art-291', lawId: 'codigo-civil-comercial', number: '291', order: 291, title: "Prohibiciones", text: "Prohibiciones. Es de ningún valor el instrumento autorizado por un funcionario público en asunto en que él, su cónyuge, su conviviente, o un pariente suyo dentro del cuarto grado o segundo de afinidad, sean personalmente interesados.", plainLanguageExplanation: "Establece el régimen de prohibiciones. Es de ningún valor el instrumento autorizado por un funcionario público en asunto en que él, su cónyuge, su conviviente, o un pariente suyo dentro del cuarto grado o segundo de afinidad, sean personalmente interesados.", practicalEffects: ['En la práctica, este artículo rige prohibiciones. Es de ningún valor el instrumento autorizado por un funcionario público en asunto en que él, su cónyuge, su conviviente, o un pariente suyo dentro del'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibicionesarticulo 291'], segments: [], amendments: [] },
  { id: 'ccyc-art-292', lawId: 'codigo-civil-comercial', number: '292', order: 292, title: "Presupuestos", text: "Presupuestos. Es presupuesto para la validez del instrumento que el oficial público se encuentre efectivamente en funciones. Sin embargo, son válidos los actos instrumentados y autorizados por él antes de la notificación de la suspensión o cesación de sus funciones hechos conforme a la ley o reglamento que regula la función de que se trata. Dentro de los límites de la buena fe, la falta de los requisitos necesarios para su nombramiento e investidura no afecta al acto ni al instrumento si la persona interviniente ejerce efectivamente un cargo existente y actúa bajo la apariencia de legitimidad del título.", plainLanguageExplanation: "Establece el régimen de presupuestos. Es presupuesto para la validez del instrumento que el oficial público se encuentre efectivamente en funciones.", practicalEffects: ['En la práctica, este artículo rige presupuestos. Es presupuesto para la validez del instrumento que el oficial público se encuentre efectivamente en funciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presupuestosarticulo 292'], segments: [], amendments: [] },
  { id: 'ccyc-art-293', lawId: 'codigo-civil-comercial', number: '293', order: 293, title: "Competencia", text: "Competencia. Los instrumentos públicos extendidos de acuerdo con lo que establece este Código gozan de entera fe y producen idénticos efectos en todo el territorio de la República, cualquiera sea la jurisdicción donde se hayan otorgado.", plainLanguageExplanation: "Establece el régimen de competencia. Los instrumentos públicos extendidos de acuerdo con lo que establece este Código gozan de entera fe y producen idénticos efectos en todo el territorio de la República, cualquiera sea la jurisdicción donde se hayan otorgado.", practicalEffects: ['En la práctica, este artículo rige competencia. Los instrumentos públicos extendidos de acuerdo con lo que establece este Código gozan de entera fe y producen idénticos efectos en todo el territorio'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['competenciaarticulo 293'], segments: [], amendments: [] },
  { id: 'ccyc-art-294', lawId: 'codigo-civil-comercial', number: '294', order: 294, title: "Defectos de forma", text: "Defectos de forma. Carece de validez el instrumento público que tenga enmiendas, agregados, borraduras, entrelíneas y alteraciones en partes esenciales, si no están salvadas antes de las firmas requeridas. El instrumento que no tenga la forma debida vale como instrumento privado si está firmado por las partes.", plainLanguageExplanation: "Establece el régimen de defectos de forma. Carece de validez el instrumento público que tenga enmiendas, agregados, borraduras, entrelíneas y alteraciones en partes esenciales, si no están salvadas antes de las firmas requeridas.", practicalEffects: ['En la práctica, este artículo rige defectos de forma. Carece de validez el instrumento público que tenga enmiendas, agregados, borraduras, entrelíneas y alteraciones en partes esenciales, si no están salvadas antes de las firmas requeridas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['defectos', 'forma', 'articulo 294'], segments: [], amendments: [] },
  { id: 'ccyc-art-295', lawId: 'codigo-civil-comercial', number: '295', order: 295, title: "Testigos inhábiles", text: "Testigos inhábiles. No pueden ser testigos en instrumentos públicos: a) las personas incapaces de ejercicio y aquellas a quienes una sentencia les impide ser testigo en instrumentos públicos; b) los que no saben firmar; c) los dependientes del oficial público; d) el cónyuge, el conviviente y los parientes del oficial público, dentro del cuarto grado y segundo de afinidad; El error común sobre la idoneidad de los testigos salva la eficacia de los instrumentos en que han intervenido.", plainLanguageExplanation: "Establece el régimen de testigos inhábiles. No pueden ser testigos en instrumentos públicos: a) las personas incapaces de ejercicio y aquellas a quienes una sentencia les impide ser testigo en instrumentos públicos; b) los que no saben firmar; c) los dependientes del oficial público; d) el cónyuge, el conviviente y los par", practicalEffects: ['En la práctica, este artículo rige testigos inhábiles. No pueden ser testigos en instrumentos públicos: a) las personas incapaces de ejercicio y aquellas a quienes una sentencia les impide ser testigo en i'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['testigos', 'inhbiles', 'articulo 295'], segments: [], amendments: [] },
  { id: 'ccyc-art-296', lawId: 'codigo-civil-comercial', number: '296', order: 296, title: "Eficacia probatoria", text: "Eficacia probatoria. El instrumento público hace plena fe: a) en cuanto a que se ha realizado el acto, la fecha, el lugar y los hechos que el oficial público enuncia como cumplidos por él o ante él hasta que sea declarado falso en juicio civil o criminal; b) en cuanto al contenido de las declaraciones sobre convenciones, disposiciones, pagos, reconocimientos y enunciaciones de hechos directamente relacionados con el objeto principal del acto instrumentado, hasta que se produzca prueba en contrario.", plainLanguageExplanation: "Establece el régimen de eficacia probatoria. El instrumento público hace plena fe: a) en cuanto a que se ha realizado el acto, la fecha, el lugar y los hechos que el oficial público enuncia como cumplidos por él o ante él hasta que sea declarado falso en juicio civil o criminal; b) en cuanto al contenido de las declaracione", practicalEffects: ['En la práctica, este artículo rige eficacia probatoria. El instrumento público hace plena fe: a) en cuanto a que se ha realizado el acto, la fecha, el lugar y los hechos que el oficial público enuncia como'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eficacia', 'probatoria', 'articulo 296'], segments: [], amendments: [] },
  { id: 'ccyc-art-297', lawId: 'codigo-civil-comercial', number: '297', order: 297, title: "Incolumidad formal", text: "Incolumidad formal. Los testigos de un instrumento público y el oficial público que lo autorizó no pueden contradecir, variar ni alterar su contenido, si no alegan que testificaron u otorgaron el acto siendo víctimas de dolo o violencia.", plainLanguageExplanation: "Establece el régimen de incolumidad formal. Los testigos de un instrumento público y el oficial público que lo autorizó no pueden contradecir, variar ni alterar su contenido, si no alegan que testificaron u otorgaron el acto siendo víctimas de dolo o violencia.", practicalEffects: ['En la práctica, este artículo rige incolumidad formal. Los testigos de un instrumento público y el oficial público que lo autorizó no pueden contradecir, variar ni alterar su contenido, si no alegan que te'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incolumidad', 'formal', 'articulo 297'], segments: [], amendments: [] },
  { id: 'ccyc-art-298', lawId: 'codigo-civil-comercial', number: '298', order: 298, title: "Contradocumento", text: "Contradocumento. El contradocumento particular que altera lo expresado en un instrumento público puede invocarse por las partes, pero es inoponible respecto a terceros interesados de buena fe. SECCION 5ª Escritura pública y acta", plainLanguageExplanation: "Establece el régimen de contradocumento. El contradocumento particular que altera lo expresado en un instrumento público puede invocarse por las partes, pero es inoponible respecto a terceros interesados de buena fe.", practicalEffects: ['En la práctica, este artículo rige contradocumento. El contradocumento particular que altera lo expresado en un instrumento público puede invocarse por las partes, pero es inoponible respecto a terceros interesados de buena fe.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contradocumentoarticulo 298'], segments: [], amendments: [] },
  { id: 'ccyc-art-299', lawId: 'codigo-civil-comercial', number: '299', order: 299, title: "Escritura pública", text: "Escritura pública. Definición. La escritura pública es el instrumento matriz extendido en el protocolo de un escribano público o de otro funcionario autorizado para ejercer las mismas funciones, que contienen uno o más actos jurídicos. La copia o testimonio de las escrituras públicas que expiden los escribanos es instrumento público y hace plena fe como la escritura matriz. Si hay alguna variación entre ésta y la copia o testimonio, se debe estar al contenido de la escritura matriz.", plainLanguageExplanation: "Establece el régimen de escritura pública. Definición.", practicalEffects: ['En la práctica, este artículo rige escritura pública. Definición.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['escritura', 'pblica', 'articulo 299'], segments: [], amendments: [] },
  { id: 'ccyc-art-300', lawId: 'codigo-civil-comercial', number: '300', order: 300, title: "Protocolo", text: "Protocolo. El protocolo se forma con los folios habilitados para el uso de cada registro, numerados correlativamente en cada año calendario, y con los documentos que se incorporan por exigencia legal o a requerimiento de las partes del acto. Corresponde a la ley local reglamentar lo relativo a las características de los folios, su expedición, así como los demás recaudos relativos al protocolo, forma y modo de su colección en volúmenes o legajos, su conservación y archivo.", plainLanguageExplanation: "Establece el régimen de protocolo. El protocolo se forma con los folios habilitados para el uso de cada registro, numerados correlativamente en cada año calendario, y con los documentos que se incorporan por exigencia legal o a requerimiento de las partes del acto.", practicalEffects: ['En la práctica, este artículo rige protocolo. El protocolo se forma con los folios habilitados para el uso de cada registro, numerados correlativamente en cada año calendario, y con los documentos'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['protocoloarticulo 300'], segments: [], amendments: [] },
  { id: 'ccyc-art-301', lawId: 'codigo-civil-comercial', number: '301', order: 301, title: "Requisitos", text: "Requisitos. El escribano debe recibir por sí mismo las declaraciones de los comparecientes, sean las partes, sus representantes, testigos, cónyuges u otros intervinientes. Debe calificar los presupuestos y elementos del acto, y configurarlo técnicamente. Las escrituras públicas, que deben extenderse en un único acto, pueden ser manuscritas o mecanografiadas, pudiendo utilizarse mecanismos electrónicos de procesamiento de textos, siempre que en definitiva la redacción resulte estampada en el soporte exigido por las reglamentaciones, con caracteres fácilmente legibles. En los casos de pluralidad de otorgantes en los que no haya entrega de dinero, valores o cosas en presencia del notario, los interesados pueden suscribir la escritura en distintas horas del mismo día de su otorgamiento. Este procedimiento puede utilizarse siempre que no se modifique el texto definitivo al tiempo de la primera firma.", plainLanguageExplanation: "Establece el régimen de requisitos. El escribano debe recibir por sí mismo las declaraciones de los comparecientes, sean las partes, sus representantes, testigos, cónyuges u otros intervinientes.", practicalEffects: ['En la práctica, este artículo rige requisitos. El escribano debe recibir por sí mismo las declaraciones de los comparecientes, sean las partes, sus representantes, testigos, cónyuges u otros intervinientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 301'], segments: [], amendments: [] },
  { id: 'ccyc-art-302', lawId: 'codigo-civil-comercial', number: '302', order: 302, title: "Idioma", text: "Idioma. La escritura pública debe hacerse en idioma nacional. Si alguno de los otorgantes declara ignorarlo, la escritura debe redactarse conforme a una minuta firmada, que debe ser expresada en idioma nacional por traductor público, y si no lo hay, por intérprete que el escribano acepte. Ambos instrumentos deben quedar agregados al protocolo. Los otorgantes pueden requerir al notario la protocolización de un instrumento original en idioma extranjero, siempre que conste de traducción efectuada por traductor público, o intérprete que aquél acepte. En tal caso, con el testimonio de la escritura, el escribano debe entregar copia certificada de ese instrumento en el idioma en que está redactado.", plainLanguageExplanation: "Establece el régimen de idioma. La escritura pública debe hacerse en idioma nacional.", practicalEffects: ['En la práctica, este artículo rige idioma. La escritura pública debe hacerse en idioma nacional.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['idiomaarticulo 302'], segments: [], amendments: [] },
  { id: 'ccyc-art-303', lawId: 'codigo-civil-comercial', number: '303', order: 303, title: "Abreviaturas y números", text: "Abreviaturas y números. No se deben dejar espacios en blanco, ni utilizar abreviaturas, o iniciales, excepto que estas dos últimas consten en los documentos que se transcriben, se trate de constancias de otros documentos agregados o sean signos o abreviaturas científicas o socialmente admitidas con sentido unívoco. Pueden usarse números, excepto para las cantidades que se entregan en presencia del escribano y otras cantidades o datos que corresponden a elementos esenciales del acto jurídico.", plainLanguageExplanation: "Establece el régimen de abreviaturas y números. No se deben dejar espacios en blanco, ni utilizar abreviaturas, o iniciales, excepto que estas dos últimas consten en los documentos que se transcriben, se trate de constancias de otros documentos agregados o sean signos o abreviaturas científicas o socialmente admitidas con sentido unívoco.", practicalEffects: ['En la práctica, este artículo rige abreviaturas y números. No se deben dejar espacios en blanco, ni utilizar abreviaturas, o iniciales, excepto que estas dos últimas consten en los documentos que se transcribe'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['abreviaturas', 'nmeros', 'articulo 303'], segments: [], amendments: [] },
  { id: 'ccyc-art-304', lawId: 'codigo-civil-comercial', number: '304', order: 304, title: "Otorgante con discapacidad auditiva", text: "Otorgante con discapacidad auditiva. Si alguna de las personas otorgantes del acto tiene discapacidad auditiva, deben intervenir dos testigos que puedan dar cuenta del conocimiento y comprensión del acto por la persona otorgante. Si es alfabeta, además, la escritura debe hacerse de conformidad a una minuta firmada por ella y el escribano debe dar fe de ese hecho. La minuta debe quedar protocolizada.", plainLanguageExplanation: "Establece el régimen de otorgante con discapacidad auditiva. Si alguna de las personas otorgantes del acto tiene discapacidad auditiva, deben intervenir dos testigos que puedan dar cuenta del conocimiento y comprensión del acto por la persona otorgante.", practicalEffects: ['En la práctica, este artículo rige otorgante con discapacidad auditiva. Si alguna de las personas otorgantes del acto tiene discapacidad auditiva, deben intervenir dos testigos que puedan dar cuenta del conocimiento y comprensión del acto por la persona otorgante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['otorgante', 'discapacidad', 'auditiva', 'articulo 304'], segments: [], amendments: [] },
  { id: 'ccyc-art-305', lawId: 'codigo-civil-comercial', number: '305', order: 305, title: "Contenido", text: "Contenido. La escritura debe contener: a) lugar y fecha de su otorgamiento; si cualquiera de las partes lo requiere o el escribano lo considera conveniente, la hora en que se firma el instrumento; b) los nombres, apellidos, documento de identidad, domicilio real y especial si lo hubiera, fecha de nacimiento y estado de familia de los otorgantes; si se trata de personas casadas, se debe consignar también si lo son en primeras o posteriores nupcias y el nombre del cónyuge, si resulta relevante en atención a la naturaleza del acto; si el otorgante es una persona jurídica, se debe dejar constancia de su denominación completa, domicilio social y datos de inscripción de su constitución si corresponde; c) la naturaleza del acto y la individualización de los bienes que constituyen su objeto; d) la constancia instrumental de la lectura que el escribano debe hacer en el acto del otorgamiento de la escritura; e) las enmiendas, testados, borraduras, entrelíneas, u otras modificaciones efectuadas al instrumento en partes esenciales, que deben ser realizadas de puño y letra del escribano y antes de la firma; f) la firma de los otorgantes, del escribano y de los testigos si los hubiera; si alguno de los otorgantes no sabe o no puede firmar, debe hacerlo en su nombre otra persona; debe hacerse constar la manifestación sobre la causa del impedimento y la impresión digital del otorgante.", plainLanguageExplanation: "Establece el régimen de contenido. La escritura debe contener: a) lugar y fecha de su otorgamiento; si cualquiera de las partes lo requiere o el escribano lo considera conveniente, la hora en que se firma el instrumento; b) los nombres, apellidos, documento de identidad, domicilio real y especial si lo hubiera, fe", practicalEffects: ['En la práctica, este artículo rige contenido. La escritura debe contener: a) lugar y fecha de su otorgamiento; si cualquiera de las partes lo requiere o el escribano lo considera conveniente, la h'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contenidoarticulo 305'], segments: [], amendments: [] },
  { id: 'ccyc-art-306', lawId: 'codigo-civil-comercial', number: '306', order: 306, title: "Justificación de identidad", text: "Justificación de identidad. La identidad de los comparecientes debe justificarse por cualquiera de los siguientes medios: a) por exhibición que se haga al escribano de documento idóneo; en este caso, se debe individualizar el documento y agregar al protocolo reproducción certificada de sus partes pertinentes; b) por afirmación del conocimiento por parte del escribano.", plainLanguageExplanation: "Establece el régimen de justificación de identidad. La identidad de los comparecientes debe justificarse por cualquiera de los siguientes medios: a) por exhibición que se haga al escribano de documento idóneo; en este caso, se debe individualizar el documento y agregar al protocolo reproducción certificada de sus partes pertinente", practicalEffects: ['En la práctica, este artículo rige justificación de identidad. La identidad de los comparecientes debe justificarse por cualquiera de los siguientes medios: a) por exhibición que se haga al escribano de documento'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['justificacin', 'identidad', 'articulo 306'], segments: [], amendments: [] },
  { id: 'ccyc-art-307', lawId: 'codigo-civil-comercial', number: '307', order: 307, title: "Documentos habilitantes", text: "Documentos habilitantes. Si el otorgante de la escritura es un representante, el escribano debe exigir la presentación del documento original que lo acredite, el que ha de quedar agre-gado al protocolo, excepto que se trate de poderes para más de un asunto o de otros documentos habilitantes que hagan necesaria la devolución, supuesto en el cual se debe agregar copia certificada por el escribano. En caso de que los documentos habilitantes ya estén protocolizados en el registro del escribano interviniente, basta con que se mencione esta circunstancia, indicando folio y año.", plainLanguageExplanation: "Establece el régimen de documentos habilitantes. Si el otorgante de la escritura es un representante, el escribano debe exigir la presentación del documento original que lo acredite, el que ha de quedar agre-gado al protocolo, excepto que se trate de poderes para más de un asunto o de otros documentos habilitantes que hagan nec", practicalEffects: ['En la práctica, este artículo rige documentos habilitantes. Si el otorgante de la escritura es un representante, el escribano debe exigir la presentación del documento original que lo acredite, el que ha de que'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['documentos', 'habilitantes', 'articulo 307'], segments: [], amendments: [] },
  { id: 'ccyc-art-308', lawId: 'codigo-civil-comercial', number: '308', order: 308, title: "Copias o testimonios", text: "Copias o testimonios. El escribano debe dar copia o testimonio de la escritura a las partes. Ese instrumento puede ser obtenido por cualquier medio de reproducción que asegure su permanencia indeleble, conforme a las reglamentaciones locales. Si alguna de las partes solicita nueva copia, el escribano debe entregarla, excepto que la escritura contenga la constancia de alguna obligación pendiente de dar o de hacer, a cargo de otra de las partes. En este caso, se debe requerir la acreditación en instrumento público de la extinción de la obligación, la conformidad del acreedor o la autorización judicial, que debe tramitar con citación de las partes del acto jurídico.", plainLanguageExplanation: "Establece el régimen de copias o testimonios. El escribano debe dar copia o testimonio de la escritura a las partes.", practicalEffects: ['En la práctica, este artículo rige copias o testimonios. El escribano debe dar copia o testimonio de la escritura a las partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['copias', 'testimonios', 'articulo 308'], segments: [], amendments: [] },
  { id: 'ccyc-art-309', lawId: 'codigo-civil-comercial', number: '309', order: 309, title: "Nulidad", text: "Nulidad. Son nulas las escrituras que no tengan la designación del tiempo y lugar en que sean hechas, el nombre de los otorgantes, la firma del escribano y de las partes, la firma a ruego de ellas cuando no saben o no pueden escribir y la firma de los dos testigos del acto cuando su presencia sea requerida. La inobservancia de las otras formalidades no anula las escrituras, pero los escribanos o funcionarios públicos pueden ser sancionados.", plainLanguageExplanation: "Establece el régimen de nulidad. Son nulas las escrituras que no tengan la designación del tiempo y lugar en que sean hechas, el nombre de los otorgantes, la firma del escribano y de las partes, la firma a ruego de ellas cuando no saben o no pueden escribir y la firma de los dos testigos del acto cuando su presencia sea requerida.", practicalEffects: ['En la práctica, este artículo rige nulidad. Son nulas las escrituras que no tengan la designación del tiempo y lugar en que sean hechas, el nombre de los otorgantes, la firma del escribano y de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidadarticulo 309'], segments: [], amendments: [] },
  { id: 'ccyc-art-310', lawId: 'codigo-civil-comercial', number: '310', order: 310, title: "Actas", text: "Actas. Se denominan actas los documentos notariales que tienen por objeto la comprobación de hechos.", plainLanguageExplanation: "Establece el régimen de actas. Se denominan actas los documentos notariales que tienen por objeto la comprobación de hechos.", practicalEffects: ['En la práctica, este artículo rige actas. Se denominan actas los documentos notariales que tienen por objeto la comprobación de hechos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actasarticulo 310'], segments: [], amendments: [] },
  { id: 'ccyc-art-311', lawId: 'codigo-civil-comercial', number: '311', order: 311, title: "Requisitos de las actas notariales", text: "Requisitos de las actas notariales. Las actas están sujetas a los requisitos de las escrituras públicas, con las siguientes modificaciones: a) se debe hacer constar el requerimiento que motiva la intervención del notario y, en su caso, la manifestación del requirente respecto al interés propio o de terceros con que actúa; b) no es necesaria la acreditación de personería ni la del interés de terceros que alega el requirente; c) no es necesario que el notario conozca o identifique a las personas con quienes trata a los efectos de realizar las notificaciones, requerimientos y otras diligencias; d) las personas requeridas o notificadas, en la medida en que el objeto de la comprobación así lo permita, deben ser previamente informadas del carácter en que interviene el notario y, en su caso, del derecho a no responder o de contestar; en este último supuesto se deben hacer constar en el documento las manifestaciones que se hagan; e) el notario puede practicar las diligencias sin la concurrencia del requirente cuando por su objeto no sea necesario; f) no requieren unidad de acto ni de redacción; pueden extenderse simultáneamente o con posterioridad a los hechos que se narran, pero en el mismo día, y pueden separarse en dos o más partes o diligencias, siguiendo el orden cronológico; g) pueden autorizarse aun cuando alguno de los interesados rehúse firmar, de lo cual debe dejarse constancia.", plainLanguageExplanation: "Establece el régimen de requisitos de las actas notariales. Las actas están sujetas a los requisitos de las escrituras públicas, con las siguientes modificaciones: a) se debe hacer constar el requerimiento que motiva la intervención del notario y, en su caso, la manifestación del requirente respecto al interés propio o de terceros con que", practicalEffects: ['En la práctica, este artículo rige requisitos de las actas notariales. Las actas están sujetas a los requisitos de las escrituras públicas, con las siguientes modificaciones: a) se debe hacer constar el requerimiento que'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos', 'actas', 'notariales', 'articulo 311'], segments: [], amendments: [] },
  { id: 'ccyc-art-312', lawId: 'codigo-civil-comercial', number: '312', order: 312, title: "Valor probatorio", text: "Valor probatorio. El valor probatorio de las actas se circunscribe a los hechos que el notario tiene a la vista, a la verificación de su existencia y su estado. En cuanto a las personas, se circunscribe a su identificación si existe, y debe dejarse constancia de las declaraciones y juicios que emiten. Las declaraciones deben referirse como mero hecho y no como contenido negocial. SECCION 6ª Instrumentos privados y particulares", plainLanguageExplanation: "Establece el régimen de valor probatorio. El valor probatorio de las actas se circunscribe a los hechos que el notario tiene a la vista, a la verificación de su existencia y su estado.", practicalEffects: ['En la práctica, este artículo rige valor probatorio. El valor probatorio de las actas se circunscribe a los hechos que el notario tiene a la vista, a la verificación de su existencia y su estado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['valor', 'probatorio', 'articulo 312'], segments: [], amendments: [] },
  { id: 'ccyc-art-313', lawId: 'codigo-civil-comercial', number: '313', order: 313, title: "Firma de los instrumentos privados", text: "Firma de los instrumentos privados. Si alguno de los firmantes de un instrumento privado no sabe o no puede firmar, puede dejarse constancia de la impresión digital o mediante la presencia de dos testigos que deben suscribir también el instrumento.", plainLanguageExplanation: "Establece el régimen de firma de los instrumentos privados. Si alguno de los firmantes de un instrumento privado no sabe o no puede firmar, puede dejarse constancia de la impresión digital o mediante la presencia de dos testigos que deben suscribir también el instrumento.", practicalEffects: ['En la práctica, este artículo rige firma de los instrumentos privados. Si alguno de los firmantes de un instrumento privado no sabe o no puede firmar, puede dejarse constancia de la impresión digital o mediante la presenc'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['firma', 'instrumentos', 'privados', 'articulo 313'], segments: [], amendments: [] },
  { id: 'ccyc-art-314', lawId: 'codigo-civil-comercial', number: '314', order: 314, title: "Reconocimiento de la firma", text: "Reconocimiento de la firma. Todo aquel contra quien se presente un instrumento cuya firma se le atribuye debe manifestar si ésta le pertenece. Los herederos pueden limitarse a mani-festar que ignoran si la firma es o no de su causante. La autenticidad de la firma puede probarse por cualquier medio. El reconocimiento de la firma importa el reconocimiento del cuerpo del instrumento privado. El instrumento privado reconocido, o declarado auténtico por sentencia, o cuya firma está certificada por escribano, no puede ser impugnado por quienes lo hayan reconocido, excepto por vicios en el acto del reconocimiento. La prueba resultante es indivisible. El documento signado con la impresión digital vale como principio de prueba por escrito y puede ser impugnado en su contenido.", plainLanguageExplanation: "Establece el régimen de reconocimiento de la firma. Todo aquel contra quien se presente un instrumento cuya firma se le atribuye debe manifestar si ésta le pertenece.", practicalEffects: ['En la práctica, este artículo rige reconocimiento de la firma. Todo aquel contra quien se presente un instrumento cuya firma se le atribuye debe manifestar si ésta le pertenece.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reconocimiento', 'firma', 'articulo 314'], segments: [], amendments: [] },
  { id: 'ccyc-art-315', lawId: 'codigo-civil-comercial', number: '315', order: 315, title: "Documento firmado en blanco", text: "Documento firmado en blanco. El firmante de un documento en blanco puede impugnar su contenido mediante la prueba de que no responde a sus instrucciones, pero no puede valerse para ello de testigos si no existe principio de prueba por escrito. El desconocimiento del firmante no debe afectar a terceros de buena fe. Cuando el documento firmado en blanco es sustraído contra la voluntad de la persona que lo guarda, esas circunstancias pueden probarse por cualquier medio. En tal caso, el contenido del instrumento no puede oponerse al firmante excepto por los terceros que acrediten su buena fe si han adquirido derechos a título oneroso en base al instrumento.", plainLanguageExplanation: "Establece el régimen de documento firmado en blanco. El firmante de un documento en blanco puede impugnar su contenido mediante la prueba de que no responde a sus instrucciones, pero no puede valerse para ello de testigos si no existe principio de prueba por escrito.", practicalEffects: ['En la práctica, este artículo rige documento firmado en blanco. El firmante de un documento en blanco puede impugnar su contenido mediante la prueba de que no responde a sus instrucciones, pero no puede valerse par'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['documento', 'firmado', 'blanco', 'articulo 315'], segments: [], amendments: [] },
  { id: 'ccyc-art-316', lawId: 'codigo-civil-comercial', number: '316', order: 316, title: "Enmiendas", text: "Enmiendas. Las raspaduras, enmiendas o entrelíneas que afectan partes esenciales del acto instrumentado deben ser salvadas con la firma de las partes. De no hacerse así, el juez debe determinar en qué medida el defecto excluye o reduce la fuerza probatoria del instrumento.", plainLanguageExplanation: "Establece el régimen de enmiendas. Las raspaduras, enmiendas o entrelíneas que afectan partes esenciales del acto instrumentado deben ser salvadas con la firma de las partes.", practicalEffects: ['En la práctica, este artículo rige enmiendas. Las raspaduras, enmiendas o entrelíneas que afectan partes esenciales del acto instrumentado deben ser salvadas con la firma de las partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['enmiendasarticulo 316'], segments: [], amendments: [] },
  { id: 'ccyc-art-317', lawId: 'codigo-civil-comercial', number: '317', order: 317, title: "Fecha cierta", text: "Fecha cierta. La eficacia probatoria de los instrumentos privados reconocidos se extiende a los terceros desde su fecha cierta. Adquieren fecha cierta el día en que acontece un hecho del que resulta como consecuencia ineludible que el documento ya estaba firmado o no pudo ser firmado después. La prueba puede producirse por cualquier medio, y debe ser apreciada rigurosamente por el juez.", plainLanguageExplanation: "Establece el régimen de fecha cierta. La eficacia probatoria de los instrumentos privados reconocidos se extiende a los terceros desde su fecha cierta.", practicalEffects: ['En la práctica, este artículo rige fecha cierta. La eficacia probatoria de los instrumentos privados reconocidos se extiende a los terceros desde su fecha cierta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fecha', 'cierta', 'articulo 317'], segments: [], amendments: [] },
  { id: 'ccyc-art-318', lawId: 'codigo-civil-comercial', number: '318', order: 318, title: "Correspondencia", text: "Correspondencia. La correspondencia, cualquiera sea el medio empleado para crearla o transmitirla, puede presentarse como prueba por el destinatario, pero la que es confidencial no puede ser utilizada sin consentimiento del remitente. Los terceros no pueden valerse de la correspondencia sin asentimiento del destinatario, y del remitente si es confidencial.", plainLanguageExplanation: "Establece el régimen de correspondencia. La correspondencia, cualquiera sea el medio empleado para crearla o transmitirla, puede presentarse como prueba por el destinatario, pero la que es confidencial no puede ser utilizada sin consentimiento del remitente.", practicalEffects: ['En la práctica, este artículo rige correspondencia. La correspondencia, cualquiera sea el medio empleado para crearla o transmitirla, puede presentarse como prueba por el destinatario, pero la que es co'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['correspondenciaarticulo 318'], segments: [], amendments: [] },
  { id: 'ccyc-art-319', lawId: 'codigo-civil-comercial', number: '319', order: 319, title: "Valor probatorio", text: "Valor probatorio. El valor probatorio de los instrumentos particulares debe ser apreciado por el juez ponderando, entre otras pautas, la congruencia entre lo sucedido y narrado, la precisión y claridad técnica del texto, los usos y prácticas del tráfico, las relaciones precedentes y la confiabilidad de los soportes utilizados y de los procedimientos técnicos que se apliquen. SECCION 7ª Contabilidad y estados contables", plainLanguageExplanation: "Establece el régimen de valor probatorio. El valor probatorio de los instrumentos particulares debe ser apreciado por el juez ponderando, entre otras pautas, la congruencia entre lo sucedido y narrado, la precisión y claridad técnica del texto, los usos y prácticas del tráfico, las relaciones precedentes y la confiabilid", practicalEffects: ['En la práctica, este artículo rige valor probatorio. El valor probatorio de los instrumentos particulares debe ser apreciado por el juez ponderando, entre otras pautas, la congruencia entre lo sucedido y'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['valor', 'probatorio', 'articulo 319'], segments: [], amendments: [] },
  { id: 'ccyc-art-320', lawId: 'codigo-civil-comercial', number: '320', order: 320, title: "Obligados", text: "Obligados. Excepciones. Están obligadas a llevar contabilidad todas las personas jurídicas privadas y quienes realizan una actividad económica organizada o son titulares de una empresa o establecimiento comercial, industrial, agropecuario o de servicios. Cualquier otra persona puede llevar contabilidad si solicita su inscripción y la habilitación de sus registros o la rubricación de los libros, como se establece en esta misma Sección. Sin perjuicio de lo establecido en leyes especiales, quedan excluidas de las obligaciones previstas en esta Sección las personas humanas que desarrollan profesiones liberales o actividades agropecuarias y conexas no ejecutadas u organizadas en forma de empresa. Se consideran conexas las actividades dirigidas a la transformación o a la enajenación de productos agropecuarios cuando están comprendidas en el ejercicio normal de tales actividades. También pueden ser eximidas de llevar contabilidad las actividades que, por el volumen de su giro, resulta inconveniente sujetar a tales deberes según determine cada jurisdicción local.", plainLanguageExplanation: "Establece el régimen de obligados. Excepciones.", practicalEffects: ['En la práctica, este artículo rige obligados. Excepciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligadosarticulo 320'], segments: [], amendments: [] },
  { id: 'ccyc-art-321', lawId: 'codigo-civil-comercial', number: '321', order: 321, title: "Modo de llevar la contabilidad", text: "Modo de llevar la contabilidad. La contabilidad debe ser llevada sobre una base uniforme de la que resulte un cuadro verídico de las actividades y de los actos que deben registrarse, de modo que se permita la individualización de las operaciones y las correspondientes cuentas acreedoras y deudoras. Los asientos deben respaldarse con la documentación respectiva, todo lo cual debe archivarse en forma metódica y que permita su localización y consulta.", plainLanguageExplanation: "Establece el régimen de modo de llevar la contabilidad. La contabilidad debe ser llevada sobre una base uniforme de la que resulte un cuadro verídico de las actividades y de los actos que deben registrarse, de modo que se permita la individualización de las operaciones y las correspondientes cuentas acreedoras y deudoras.", practicalEffects: ['En la práctica, este artículo rige modo de llevar la contabilidad. La contabilidad debe ser llevada sobre una base uniforme de la que resulte un cuadro verídico de las actividades y de los actos que deben registrarse,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modo', 'llevar', 'contabilidad', 'articulo 321'], segments: [], amendments: [] },
  { id: 'ccyc-art-322', lawId: 'codigo-civil-comercial', number: '322', order: 322, title: "Registros indispensables", text: "Registros indispensables. Son registros indispensables, los siguientes: a) diario; b) inventario y balances; c) aquellos que corresponden a una adecuada integración de un sistema de contabilidad y que exige la importancia y la naturaleza de las actividades a desarrollar; d) los que en forma especial impone este Código u otras leyes.", plainLanguageExplanation: "Establece el régimen de registros indispensables. Son registros indispensables, los siguientes: a) diario; b) inventario y balances; c) aquellos que corresponden a una adecuada integración de un sistema de contabilidad y que exige la importancia y la naturaleza de las actividades a desarrollar; d) los que en forma especial impon", practicalEffects: ['En la práctica, este artículo rige registros indispensables. Son registros indispensables, los siguientes: a) diario; b) inventario y balances; c) aquellos que corresponden a una adecuada integración de un siste'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['registros', 'indispensables', 'articulo 322'], segments: [], amendments: [] },
  { id: 'ccyc-art-323', lawId: 'codigo-civil-comercial', number: '323', order: 323, title: "Libros", text: "Libros. El interesado debe llevar su contabilidad mediante la utilización de libros y debe presentarlos, debidamente encuadernados, para su individualización en el Registro Público correspondiente. Tal individualización consiste en anotar, en el primer folio, nota fechada y firmada de su destino, del número de ejemplar, del nombre de su titular y del número de folios que contiene. El Registro debe llevar una nómina alfabética, de consulta pública, de las personas que solicitan rubricación de libros o autorización para llevar los registros contables de otra forma, de la que surgen los libros que les fueron rubricados y, en su caso, de las autorizaciones que se les confieren.", plainLanguageExplanation: "Establece el régimen de libros. El interesado debe llevar su contabilidad mediante la utilización de libros y debe presentarlos, debidamente encuadernados, para su individualización en el Registro Público correspondiente.", practicalEffects: ['En la práctica, este artículo rige libros. El interesado debe llevar su contabilidad mediante la utilización de libros y debe presentarlos, debidamente encuadernados, para su individualización en el Registro Público correspondiente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['librosarticulo 323'], segments: [], amendments: [] },
  { id: 'ccyc-art-324', lawId: 'codigo-civil-comercial', number: '324', order: 324, title: "Prohibiciones", text: "Prohibiciones. Se prohíbe: a) alterar el orden en que los asientos deben ser hechos; b) dejar blancos que puedan utilizarse para intercalaciones o adiciones entre los asientos; c) interlinear, raspar, emendar o tachar. Todas las equivocaciones y omisiones deben salvarse mediante un nuevo asiento hecho en la fecha en que se advierta la omisión o el error; d) mutilar parte alguna del libro, arrancar hojas o alterar la encuadernación o foliatura; e) cualquier otra circunstancia que afecte la inalterabilidad de las registraciones.", plainLanguageExplanation: "Establece el régimen de prohibiciones. Se prohíbe: a) alterar el orden en que los asientos deben ser hechos; b) dejar blancos que puedan utilizarse para intercalaciones o adiciones entre los asientos; c) interlinear, raspar, emendar o tachar.", practicalEffects: ['En la práctica, este artículo rige prohibiciones. Se prohíbe: a) alterar el orden en que los asientos deben ser hechos; b) dejar blancos que puedan utilizarse para intercalaciones o adiciones entre lo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibicionesarticulo 324'], segments: [], amendments: [] },
  { id: 'ccyc-art-325', lawId: 'codigo-civil-comercial', number: '325', order: 325, title: "Forma de llevar los registros", text: "Forma de llevar los registros. Los libros y registros contables deben ser llevados en forma cronológica, actualizada, sin alteración alguna que no haya sido debidamente salvada. También deben llevarse en idioma y moneda nacional. Deben permitir determinar al cierre de cada ejercicio económico anual la situación patrimonial, su evolución y sus resultados. Los libros y registros del artículo 322 deben permanecer en el domicilio de su titular.", plainLanguageExplanation: "Establece el régimen de forma de llevar los registros. Los libros y registros contables deben ser llevados en forma cronológica, actualizada, sin alteración alguna que no haya sido debidamente salvada.", practicalEffects: ['En la práctica, este artículo rige forma de llevar los registros. Los libros y registros contables deben ser llevados en forma cronológica, actualizada, sin alteración alguna que no haya sido debidamente salvada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma', 'llevar', 'registros', 'articulo 325'], segments: [], amendments: [] },
  { id: 'ccyc-art-326', lawId: 'codigo-civil-comercial', number: '326', order: 326, title: "Estados contables", text: "Estados contables. Al cierre del ejercicio quien lleva contabilidad obligada o voluntaria debe confeccionar sus estados contables, que comprenden como mínimo un estado de situación patrimonial y un estado de resultados que deben asentarse en el registro de inventarios y balances.", plainLanguageExplanation: "Establece el régimen de estados contables. Al cierre del ejercicio quien lleva contabilidad obligada o voluntaria debe confeccionar sus estados contables, que comprenden como mínimo un estado de situación patrimonial y un estado de resultados que deben asentarse en el registro de inventarios y balances.", practicalEffects: ['En la práctica, este artículo rige estados contables. Al cierre del ejercicio quien lleva contabilidad obligada o voluntaria debe confeccionar sus estados contables, que comprenden como mínimo un estado d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['estados', 'contables', 'articulo 326'], segments: [], amendments: [] },
  { id: 'ccyc-art-327', lawId: 'codigo-civil-comercial', number: '327', order: 327, title: "Diario", text: "Diario. En el Diario se deben registrar todas las operaciones relativas a la actividad de la persona que tienen efecto sobre el patrimonio, individualmente o en registros resumidos que cubran períodos de duración no superiores al mes. Estos resúmenes deben surgir de anotaciones detalladas practicadas en subdiarios, los que deben ser llevados en las formas y condiciones establecidas en los artículos 323, 324 y 325. El registro o Libro Caja y todo otro diario auxiliar que forma parte del sistema de registraciones contables integra el Diario y deben cumplirse las formalidades establecidas para el mismo.", plainLanguageExplanation: "Establece el régimen de diario. En el Diario se deben registrar todas las operaciones relativas a la actividad de la persona que tienen efecto sobre el patrimonio, individualmente o en registros resumidos que cubran períodos de duración no superiores al mes.", practicalEffects: ['En la práctica, este artículo rige diario. En el Diario se deben registrar todas las operaciones relativas a la actividad de la persona que tienen efecto sobre el patrimonio, individualmente o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['diarioarticulo 327'], segments: [], amendments: [] },
  { id: 'ccyc-art-328', lawId: 'codigo-civil-comercial', number: '328', order: 328, title: "Conservación", text: "Conservación. Excepto que leyes especiales establezcan plazos superiores, deben conservarse por diez años: a) los libros, contándose el plazo desde el último asiento; b) los demás registros, desde la fecha de la última anotación practicada sobre los mismos; c) los instrumentos respaldatorios, desde su fecha. Los herederos deben conservar los libros del causante y, en su caso, exhibirlos en la forma prevista en el artículo 331, hasta que se cumplan los plazos indicados anteriormente.", plainLanguageExplanation: "Establece el régimen de conservación. Excepto que leyes especiales establezcan plazos superiores, deben conservarse por diez años: a) los libros, contándose el plazo desde el último asiento; b) los demás registros, desde la fecha de la última anotación practicada sobre los mismos; c) los instrumentos respaldatorios, desde su fecha.", practicalEffects: ['En la práctica, este artículo rige conservación. Excepto que leyes especiales establezcan plazos superiores, deben conservarse por diez años: a) los libros, contándose el plazo desde el último asient'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conservacinarticulo 328'], segments: [], amendments: [] },
  { id: 'ccyc-art-329', lawId: 'codigo-civil-comercial', number: '329', order: 329, title: "Actos sujetos a autorización", text: "Actos sujetos a autorización. El titular puede, previa autorización del Registro Público de su domicilio: a) sustituir uno o más libros, excepto el de Inventarios y Balances, o alguna de sus formalidades, por la utilización de ordenadores u otros medios mecánicos, magnéticos o electrónicos que permitan la individualización de las operaciones y de las correspondientes cuentas deudoras y acreedoras y su posterior verificación; b) conservar la documentación en microfilm, discos ópticos u otros medios aptos para ese fin. La petición que se formule al Registro Público debe contener una adecuada descripción del sistema, con dictamen técnico de Contador Público e indicación de los antecedentes de su utilización. Una vez aprobado, el pedido de autorización y la respectiva resolución del organismo de contralor, deben transcribirse en el libro de Inventarios y Balances. La autorización sólo se debe otorgar si los medios alternativos son equivalentes, en cuanto a inviolabilidad, verosimilitud y completitud, a los sistemas cuyo reemplazo se solicita.", plainLanguageExplanation: "Establece el régimen de actos sujetos a autorización. El titular puede, previa autorización del Registro Público de su domicilio: a) sustituir uno o más libros, excepto el de Inventarios y Balances, o alguna de sus formalidades, por la utilización de ordenadores u otros medios mecánicos, magnéticos o electrónicos que permitan la ind", practicalEffects: ['En la práctica, este artículo rige actos sujetos a autorización. El titular puede, previa autorización del Registro Público de su domicilio: a) sustituir uno o más libros, excepto el de Inventarios y Balances, o alg'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'sujetos', 'autorizacin', 'articulo 329'], segments: [], amendments: [] },
  { id: 'ccyc-art-330', lawId: 'codigo-civil-comercial', number: '330', order: 330, title: "Eficacia probatoria", text: "Eficacia probatoria. La contabilidad, obligada o voluntaria, llevada en la forma y con los requisitos prescritos, debe ser admitida en juicio, como medio de prueba. Sus registros prueban contra quien la lleva o sus sucesores, aunque no estuvieran en forma, sin admitírseles prueba en contrario. El adversario no puede aceptar los asientos que le son favorables y desechar los que le perjudican, sino que habiendo adoptado este medio de prueba, debe estarse a las resultas combinadas que presenten todos los registros relativos al punto cuestionado. La contabilidad, obligada o voluntaria, prueba en favor de quien la lleva, cuando en litigio contra otro sujeto que tiene contabilidad, obligada o voluntaria, éste no presenta registros contrarios incorporados en una contabilidad regular. Sin embargo, el juez tiene en tal caso la facultad de apreciar esa prueba, y de exigir, si lo considera necesario, otra supletoria. Cuando resulta prueba contradictoria de los registros de las partes que litigan, y unos y otros se hallan con todas las formalidades necesarias y sin vicio alguno, el juez debe prescindir de este medio de prueba y proceder por los méritos de las demás probanzas que se presentan. Si se trata de litigio contra quien no está obligado a llevar contabilidad, ni la lleva voluntariamente, ésta sólo sirve como principio de prueba de acuerdo con las circunstancias del caso. La prueba que resulta de la contabilidad es indivisible.", plainLanguageExplanation: "Establece el régimen de eficacia probatoria. La contabilidad, obligada o voluntaria, llevada en la forma y con los requisitos prescritos, debe ser admitida en juicio, como medio de prueba.", practicalEffects: ['En la práctica, este artículo rige eficacia probatoria. La contabilidad, obligada o voluntaria, llevada en la forma y con los requisitos prescritos, debe ser admitida en juicio, como medio de prueba.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eficacia', 'probatoria', 'articulo 330'], segments: [], amendments: [] },
  { id: 'ccyc-art-331', lawId: 'codigo-civil-comercial', number: '331', order: 331, title: "Investigaciones", text: "Investigaciones. Excepto los supuestos previstos en leyes especiales, ninguna autoridad, bajo pretexto alguno, puede hacer pesquisas de oficio para inquirir si las personas llevan o no registros arreglados a derecho. La prueba sobre la contabilidad debe realizarse en el lugar previsto en el artículo 325, aun cuando esté fuera de la competencia territorial del juez que la ordena. La exhibición general de registros o libros contables sólo puede decretarse a instancia de parte en los juicios de sucesión, todo tipo de comunión, contrato asociativo o sociedad, administración por cuenta ajena y en caso de liquidación, concurso o quiebra. Fuera de estos casos únicamente puede requerirse la exhibición de registros o libros en cuanto tenga relación con la cuestión controvertida de que se trata, así como para establecer si el sistema contable del obligado cumple con las formas y condiciones establecidas en los artículos 323, 324 y 325. CAPITULO 6 Vicios de los actos jurídicos SECCION 1ª Lesión", plainLanguageExplanation: "Establece el régimen de investigaciones. Excepto los supuestos previstos en leyes especiales, ninguna autoridad, bajo pretexto alguno, puede hacer pesquisas de oficio para inquirir si las personas llevan o no registros arreglados a derecho.", practicalEffects: ['En la práctica, este artículo rige investigaciones. Excepto los supuestos previstos en leyes especiales, ninguna autoridad, bajo pretexto alguno, puede hacer pesquisas de oficio para inquirir si las personas llevan o no registros arreglados a derecho.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['investigacionesarticulo 331'], segments: [], amendments: [] },
  { id: 'ccyc-art-332', lawId: 'codigo-civil-comercial', number: '332', order: 332, title: "Lesión", text: "Lesión. Puede demandarse la nulidad o la modificación de los actos jurídicos cuando una de las partes explotando la necesidad, debilidad síquica o inexperiencia de la otra, obtuviera por medio de ellos una ventaja patrimonial evidentemente desproporcionada y sin justificación. Se presume, excepto prueba en contrario, que existe tal explotación en caso de notable desproporción de las prestaciones. Los cálculos deben hacerse según valores al tiempo del acto y la desproporción debe subsistir en el momento de la demanda. El afectado tiene opción para demandar la nulidad o un reajuste equitativo del convenio, pero la primera de estas acciones se debe transformar en acción de reajuste si éste es ofrecido por el demandado al contestar la demanda. Sólo el lesionado o sus herederos pueden ejercer la acción. SECCION 2ª Simulación &gt;", plainLanguageExplanation: "Establece el régimen de lesión. Puede demandarse la nulidad o la modificación de los actos jurídicos cuando una de las partes explotando la necesidad, debilidad síquica o inexperiencia de la otra, obtuviera por medio de ellos una ventaja patrimonial evidentemente desproporcionada y sin justificación.", practicalEffects: ['En la práctica, este artículo rige lesión. Puede demandarse la nulidad o la modificación de los actos jurídicos cuando una de las partes explotando la necesidad, debilidad síquica o inexperienc'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lesinarticulo 332'], segments: [], amendments: [] },
  { id: 'ccyc-art-333', lawId: 'codigo-civil-comercial', number: '333', order: 333, title: "Caracterización", text: "Caracterización. La simulación tiene lugar cuando se encubre el carácter jurídico de un acto bajo la apariencia de otro, o cuando el acto contiene cláusulas que no son sinceras, o fechas que no son verdaderas, o cuando por él se constituyen o transmiten derechos a personas interpuestas, que no son aquellas para quienes en realidad se constituyen o transmiten.", plainLanguageExplanation: "Establece el régimen de caracterización. La simulación tiene lugar cuando se encubre el carácter jurídico de un acto bajo la apariencia de otro, o cuando el acto contiene cláusulas que no son sinceras, o fechas que no son verdaderas, o cuando por él se constituyen o transmiten derechos a personas interpuestas, que no so", practicalEffects: ['En la práctica, este artículo rige caracterización. La simulación tiene lugar cuando se encubre el carácter jurídico de un acto bajo la apariencia de otro, o cuando el acto contiene cláusulas que no son'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caracterizacinarticulo 333'], segments: [], amendments: [] },
  { id: 'ccyc-art-334', lawId: 'codigo-civil-comercial', number: '334', order: 334, title: "Simulación lícita e ilícita", text: "Simulación lícita e ilícita. La simulación ilícita o que perjudica a un tercero provoca la nulidad del acto ostensible. Si el acto simulado encubre otro real, éste es plenamente eficaz si concurren los requisitos propios de su categoría y no es ilícito ni perjudica a un tercero. Las mismas disposiciones rigen en el caso de cláusulas simuladas.", plainLanguageExplanation: "Establece el régimen de simulación lícita e ilícita. La simulación ilícita o que perjudica a un tercero provoca la nulidad del acto ostensible.", practicalEffects: ['En la práctica, este artículo rige simulación lícita e ilícita. La simulación ilícita o que perjudica a un tercero provoca la nulidad del acto ostensible.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['simulacin', 'lcita', 'ilcita', 'articulo 334'], segments: [], amendments: [] },
  { id: 'ccyc-art-335', lawId: 'codigo-civil-comercial', number: '335', order: 335, title: "Acción entre las partes", text: "Acción entre las partes. Contradocumento. Los que otorgan un acto simulado ilícito o que perjudica a terceros no pueden ejercer acción alguna el uno contra el otro sobre la simula-ción, excepto que las partes no puedan obtener beneficio alguno de las resultas del ejercicio de la acción de simulación. La simulación alegada por las partes debe probarse mediante el respectivo contradocumento. Puede prescindirse de él, cuando la parte justifica las razones por las cuales no existe o no puede ser presentado y median circunstancias que hacen inequívoca la simulación.", plainLanguageExplanation: "Establece el régimen de acción entre las partes. Contradocumento.", practicalEffects: ['En la práctica, este artículo rige acción entre las partes. Contradocumento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'entre', 'partes', 'articulo 335'], segments: [], amendments: [] },
  { id: 'ccyc-art-336', lawId: 'codigo-civil-comercial', number: '336', order: 336, title: "Acción de terceros", text: "Acción de terceros. Los terceros cuyos derechos o intereses legítimos son afectados por el acto simulado pueden demandar su nulidad. Pueden acreditar la simulación por cualquier medio de prueba.", plainLanguageExplanation: "Establece el régimen de acción de terceros. Los terceros cuyos derechos o intereses legítimos son afectados por el acto simulado pueden demandar su nulidad.", practicalEffects: ['En la práctica, este artículo rige acción de terceros. Los terceros cuyos derechos o intereses legítimos son afectados por el acto simulado pueden demandar su nulidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'terceros', 'articulo 336'], segments: [], amendments: [] },
  { id: 'ccyc-art-337', lawId: 'codigo-civil-comercial', number: '337', order: 337, title: "Efectos frente a terceros", text: "Efectos frente a terceros. Deber de indemnizar. La simulación no puede oponerse a los acreedores del adquirente simulado que de buena fe hayan ejecutado los bienes comprendidos en el acto. La acción del acreedor contra el subadquirente de los derechos obtenidos por el acto impugnado sólo procede si adquirió por título gratuito, o si es cómplice en la simulación. El subadquirente de mala fe y quien contrató de mala fe con el deudor responden solidariamente por los daños causados al acreedor que ejerció la acción, si los derechos se transmitieron a un adquirente de buena fe y a título oneroso, o de otro modo se perdieron para el acreedor. El que contrató de buena fe y a título gratuito con el deudor, responde en la medida de su enriquecimiento. SECCION 3ª Fraude", plainLanguageExplanation: "Establece el régimen de efectos frente a terceros. Deber de indemnizar.", practicalEffects: ['En la práctica, este artículo rige efectos frente a terceros. Deber de indemnizar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'frente', 'terceros', 'articulo 337'], segments: [], amendments: [] },
  { id: 'ccyc-art-338', lawId: 'codigo-civil-comercial', number: '338', order: 338, title: "Declaración de inoponibilidad", text: "Declaración de inoponibilidad. Todo acreedor puede solicitar la declaración de inoponibilidad de los actos celebrados por su deudor en fraude de sus derechos, y de las renuncias al ejercicio de derechos o facultades con los que hubiese podido mejorar o evitado empeorar su estado de fortuna.", plainLanguageExplanation: "Establece el régimen de declaración de inoponibilidad. Todo acreedor puede solicitar la declaración de inoponibilidad de los actos celebrados por su deudor en fraude de sus derechos, y de las renuncias al ejercicio de derechos o facultades con los que hubiese podido mejorar o evitado empeorar su estado de fortuna.", practicalEffects: ['En la práctica, este artículo rige declaración de inoponibilidad. Todo acreedor puede solicitar la declaración de inoponibilidad de los actos celebrados por su deudor en fraude de sus derechos, y de las renuncias al'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['declaracin', 'inoponibilidad', 'articulo 338'], segments: [], amendments: [] },
  { id: 'ccyc-art-339', lawId: 'codigo-civil-comercial', number: '339', order: 339, title: "Requisitos", text: "Requisitos. Son requisitos de procedencia de la acción de declaración de inoponibilidad: a) que el crédito sea de causa anterior al acto impugnado, excepto que el deudor haya actuado con el propósito de defraudar a futuros acreedores; b) que el acto haya causado o agravado la insolvencia del deudor; c) que quien contrató con el deudor a título oneroso haya conocido o debido conocer que el acto provocaba o agravaba la insolvencia.", plainLanguageExplanation: "Establece el régimen de requisitos. Son requisitos de procedencia de la acción de declaración de inoponibilidad: a) que el crédito sea de causa anterior al acto impugnado, excepto que el deudor haya actuado con el propósito de defraudar a futuros acreedores; b) que el acto haya causado o agravado la insolvencia del", practicalEffects: ['En la práctica, este artículo rige requisitos. Son requisitos de procedencia de la acción de declaración de inoponibilidad: a) que el crédito sea de causa anterior al acto impugnado, excepto que el'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 339'], segments: [], amendments: [] },
  { id: 'ccyc-art-340', lawId: 'codigo-civil-comercial', number: '340', order: 340, title: "Efectos frente a terceros", text: "Efectos frente a terceros. Deber de indemnizar. El fraude no puede oponerse a los acreedores del adquirente que de buena fe hayan ejecutado los bienes comprendidos en el acto. La acción del acreedor contra el subadquirente de los derechos obtenidos por el acto impugnado sólo procede si adquirió por título gratuito, o si es cómplice en el fraude; la complicidad se presume si, al momento de contratar, conocía el estado de insolvencia. El subadquirente de mala fe y quien contrató de mala fe con el deudor responden solidariamente por los daños causados al acreedor que ejerció la acción, si los derechos se transmitieron a un adquirente de buena fe y a título oneroso, o de otro modo se perdieron para el acreedor. El que contrató de buena fe y a título gratuito con el deudor, responde en la medida de su enriquecimiento.", plainLanguageExplanation: "Establece el régimen de efectos frente a terceros. Deber de indemnizar.", practicalEffects: ['En la práctica, este artículo rige efectos frente a terceros. Deber de indemnizar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'frente', 'terceros', 'articulo 340'], segments: [], amendments: [] },
  { id: 'ccyc-art-341', lawId: 'codigo-civil-comercial', number: '341', order: 341, title: "Extinción de la acción", text: "Extinción de la acción. Cesa la acción de los acreedores si el adquirente de los bienes transmitidos por el deudor los desinteresa o da garantía suficiente.", plainLanguageExplanation: "Establece el régimen de extinción de la acción. Cesa la acción de los acreedores si el adquirente de los bienes transmitidos por el deudor los desinteresa o da garantía suficiente.", practicalEffects: ['En la práctica, este artículo rige extinción de la acción. Cesa la acción de los acreedores si el adquirente de los bienes transmitidos por el deudor los desinteresa o da garantía suficiente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'accin', 'articulo 341'], segments: [], amendments: [] },
  { id: 'ccyc-art-342', lawId: 'codigo-civil-comercial', number: '342', order: 342, title: "Extensión de la inoponibilidad", text: "Extensión de la inoponibilidad. La declaración de inoponibilidad se pronuncia exclusivamente en interés de los acreedores que la promueven, y hasta el importe de sus respectivos créditos. CAPITULO 7 Modalidades de los actos jurídicos SECCION 1ª Condición", plainLanguageExplanation: "Establece el régimen de extensión de la inoponibilidad. La declaración de inoponibilidad se pronuncia exclusivamente en interés de los acreedores que la promueven, y hasta el importe de sus respectivos créditos.", practicalEffects: ['En la práctica, este artículo rige extensión de la inoponibilidad. La declaración de inoponibilidad se pronuncia exclusivamente en interés de los acreedores que la promueven, y hasta el importe de sus respectivos créditos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extensin', 'inoponibilidad', 'articulo 342'], segments: [], amendments: [] },
  { id: 'ccyc-art-343', lawId: 'codigo-civil-comercial', number: '343', order: 343, title: "Alcance y especies", text: "Alcance y especies. Se denomina condición a la cláusula de los actos jurídicos por la cual las partes subordinan su plena eficacia o resolución a un hecho futuro e incierto. Las disposiciones de este capítulo son aplicables, en cuanto fueran compatibles, a la cláusula por la cual las partes sujetan la adquisición o extinción de un derecho a hechos presentes o pasados ignorados.", plainLanguageExplanation: "Establece el régimen de alcance y especies. Se denomina condición a la cláusula de los actos jurídicos por la cual las partes subordinan su plena eficacia o resolución a un hecho futuro e incierto.", practicalEffects: ['En la práctica, este artículo rige alcance y especies. Se denomina condición a la cláusula de los actos jurídicos por la cual las partes subordinan su plena eficacia o resolución a un hecho futuro e incierto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alcance', 'especies', 'articulo 343'], segments: [], amendments: [] },
  { id: 'ccyc-art-344', lawId: 'codigo-civil-comercial', number: '344', order: 344, title: "Condiciones prohibidas", text: "Condiciones prohibidas. Es nulo el acto sujeto a un hecho imposible, contrario a la moral y a las buenas costumbres, prohibido por el ordenamiento jurídico o que depende exclusivamente de la voluntad del obligado. La condición de no hacer una cosa imposible no perjudica la validez de la obligación, si ella fuera pactada bajo modalidad suspensiva. Se tienen por no escritas las condiciones que afecten de modo grave las libertades de la persona, como la de elegir domicilio o religión, o decidir sobre su estado civil.", plainLanguageExplanation: "Establece el régimen de condiciones prohibidas. Es nulo el acto sujeto a un hecho imposible, contrario a la moral y a las buenas costumbres, prohibido por el ordenamiento jurídico o que depende exclusivamente de la voluntad del obligado.", practicalEffects: ['En la práctica, este artículo rige condiciones prohibidas. Es nulo el acto sujeto a un hecho imposible, contrario a la moral y a las buenas costumbres, prohibido por el ordenamiento jurídico o que depende exclusivamente de la voluntad del obligado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['condiciones', 'prohibidas', 'articulo 344'], segments: [], amendments: [] },
  { id: 'ccyc-art-345', lawId: 'codigo-civil-comercial', number: '345', order: 345, title: "Inejecución de la condición", text: "Inejecución de la condición. El incumplimiento de la condición no puede ser invocado por la parte que, de mala fe, impide su realización.", plainLanguageExplanation: "Establece el régimen de inejecución de la condición. El incumplimiento de la condición no puede ser invocado por la parte que, de mala fe, impide su realización.", practicalEffects: ['En la práctica, este artículo rige inejecución de la condición. El incumplimiento de la condición no puede ser invocado por la parte que, de mala fe, impide su realización.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inejecucin', 'condicin', 'articulo 345'], segments: [], amendments: [] },
  { id: 'ccyc-art-346', lawId: 'codigo-civil-comercial', number: '346', order: 346, title: "Efecto", text: "Efecto. La condición no opera retroactivamente, excepto pacto en contrario.", plainLanguageExplanation: "Establece el régimen de efecto. La condición no opera retroactivamente, excepto pacto en contrario.", practicalEffects: ['En la práctica, este artículo rige efecto. La condición no opera retroactivamente, excepto pacto en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectoarticulo 346'], segments: [], amendments: [] },
  { id: 'ccyc-art-347', lawId: 'codigo-civil-comercial', number: '347', order: 347, title: "Condición pendiente", text: "Condición pendiente. El titular de un derecho supeditado a condición suspensiva puede solicitar medidas conservatorias. El adquirente de un derecho sujeto a condición resolutoria puede ejercerlo, pero la otra parte puede solicitar, también medidas conservatorias. En todo supuesto, mientras la condición no se haya cumplido, la parte que constituyó o transmitió un derecho debe comportarse de acuerdo con la buena fe, de modo de no perjudicar a la contraparte.", plainLanguageExplanation: "Establece el régimen de condición pendiente. El titular de un derecho supeditado a condición suspensiva puede solicitar medidas conservatorias.", practicalEffects: ['En la práctica, este artículo rige condición pendiente. El titular de un derecho supeditado a condición suspensiva puede solicitar medidas conservatorias.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['condicin', 'pendiente', 'articulo 347'], segments: [], amendments: [] },
  { id: 'ccyc-art-348', lawId: 'codigo-civil-comercial', number: '348', order: 348, title: "Cumplimiento de la condición suspensiva y resolutoria", text: "Cumplimiento de la condición suspensiva y resolutoria. El cumplimiento de la condición obliga a las partes a entregarse o restituirse, recíprocamente, las prestaciones convenidas, aplicándose los efectos correspondientes a la naturaleza del acto concertado, a sus fines y objeto. Si se hubiese determinado el efecto retroactivo de la condición, el cumplimiento de ésta obliga a la entrega recíproca de lo que a las partes habría correspondido al tiempo de la celebración del acto. No obstante, subsisten los actos de administración y los frutos quedan a favor de la parte que los ha percibido.", plainLanguageExplanation: "Establece el régimen de cumplimiento de la condición suspensiva y resolutoria. El cumplimiento de la condición obliga a las partes a entregarse o restituirse, recíprocamente, las prestaciones convenidas, aplicándose los efectos correspondientes a la naturaleza del acto concertado, a sus fines y objeto.", practicalEffects: ['En la práctica, este artículo rige cumplimiento de la condición suspensiva y resolutoria. El cumplimiento de la condición obliga a las partes a entregarse o restituirse, recíprocamente, las prestaciones convenidas, aplicándose los efectos c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cumplimiento', 'condicin', 'suspensiva', 'resolutoria', 'articulo 348'], segments: [], amendments: [] },
  { id: 'ccyc-art-349', lawId: 'codigo-civil-comercial', number: '349', order: 349, title: "No cumplimiento de la condición suspensiva", text: "No cumplimiento de la condición suspensiva. Si el acto celebrado bajo condición suspensiva se hubiese ejecutado antes del cumplimiento de la condición, y ésta no se cumple, debe restituirse el objeto con sus accesorios pero no los frutos percibidos. SECCION 2ª Plazo", plainLanguageExplanation: "Establece el régimen de no cumplimiento de la condición suspensiva. Si el acto celebrado bajo condición suspensiva se hubiese ejecutado antes del cumplimiento de la condición, y ésta no se cumple, debe restituirse el objeto con sus accesorios pero no los frutos percibidos.", practicalEffects: ['En la práctica, este artículo rige no cumplimiento de la condición suspensiva. Si el acto celebrado bajo condición suspensiva se hubiese ejecutado antes del cumplimiento de la condición, y ésta no se cumple, debe restituirse el o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cumplimiento', 'condicin', 'suspensiva', 'articulo 349'], segments: [], amendments: [] },
  { id: 'ccyc-art-350', lawId: 'codigo-civil-comercial', number: '350', order: 350, title: "Especies", text: "Especies. La exigibilidad o la extinción de un acto jurídico pueden quedar diferidas al vencimiento de un plazo.", plainLanguageExplanation: "Establece el régimen de especies. La exigibilidad o la extinción de un acto jurídico pueden quedar diferidas al vencimiento de un plazo.", practicalEffects: ['En la práctica, este artículo rige especies. La exigibilidad o la extinción de un acto jurídico pueden quedar diferidas al vencimiento de un plazo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['especiesarticulo 350'], segments: [], amendments: [] },
  { id: 'ccyc-art-351', lawId: 'codigo-civil-comercial', number: '351', order: 351, title: "Beneficiario del plazo", text: "Beneficiario del plazo. El plazo se presume establecido en beneficio del obligado a cumplir o a restituir a su vencimiento, a no ser que, por la naturaleza del acto, o por otras circunstancias, resulte que ha sido previsto a favor del acreedor o de ambas partes.", plainLanguageExplanation: "Establece el régimen de beneficiario del plazo. El plazo se presume establecido en beneficio del obligado a cumplir o a restituir a su vencimiento, a no ser que, por la naturaleza del acto, o por otras circunstancias, resulte que ha sido previsto a favor del acreedor o de ambas partes.", practicalEffects: ['En la práctica, este artículo rige beneficiario del plazo. El plazo se presume establecido en beneficio del obligado a cumplir o a restituir a su vencimiento, a no ser que, por la naturaleza del acto, o por ot'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['beneficiario', 'plazo', 'articulo 351'], segments: [], amendments: [] },
  { id: 'ccyc-art-352', lawId: 'codigo-civil-comercial', number: '352', order: 352, title: "Pago anticipado", text: "Pago anticipado. El obligado que cumple o restituye antes del plazo no puede repetir lo pagado.", plainLanguageExplanation: "Establece el régimen de pago anticipado. El obligado que cumple o restituye antes del plazo no puede repetir lo pagado.", practicalEffects: ['En la práctica, este artículo rige pago anticipado. El obligado que cumple o restituye antes del plazo no puede repetir lo pagado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'anticipado', 'articulo 352'], segments: [], amendments: [] },
  { id: 'ccyc-art-353', lawId: 'codigo-civil-comercial', number: '353', order: 353, title: "Caducidad del plazo", text: "Caducidad del plazo. El obligado a cumplir no puede invocar la pendencia del plazo si se ha declarado su quiebra, si disminuye por acto propio las seguridades otorgadas al acreedor para el cumplimiento de la obligación, o si no ha constituido las garantías prometidas, entre otros supuestos relevantes. La apertura del concurso del obligado al pago no hace caducar el plazo, sin perjuicio del derecho del acreedor a verificar su crédito, y a todas las consecuencias previstas en la legislación concursal. SECCION 3ª Cargo", plainLanguageExplanation: "Establece el régimen de caducidad del plazo. El obligado a cumplir no puede invocar la pendencia del plazo si se ha declarado su quiebra, si disminuye por acto propio las seguridades otorgadas al acreedor para el cumplimiento de la obligación, o si no ha constituido las garantías prometidas, entre otros supuestos relevantes.", practicalEffects: ['En la práctica, este artículo rige caducidad del plazo. El obligado a cumplir no puede invocar la pendencia del plazo si se ha declarado su quiebra, si disminuye por acto propio las seguridades otorgadas al'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caducidad', 'plazo', 'articulo 353'], segments: [], amendments: [] },
  { id: 'ccyc-art-354', lawId: 'codigo-civil-comercial', number: '354', order: 354, title: "Cargo", text: "Cargo. Especies. Presunción. El cargo es una obligación accesoria impuesta al adquirente de un derecho. No impide los efectos del acto, excepto que su cumplimiento se haya previsto como condición suspensiva, ni los resuelve, excepto que su cumplimiento se haya estipulado como condición resolutoria. En caso de duda, se entiende que tal condición no existe.", plainLanguageExplanation: "Establece el régimen de cargo. Especies.", practicalEffects: ['En la práctica, este artículo rige cargo. Especies.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cargoarticulo 354'], segments: [], amendments: [] },
  { id: 'ccyc-art-355', lawId: 'codigo-civil-comercial', number: '355', order: 355, title: "Tiempo de cumplimiento", text: "Tiempo de cumplimiento. Prescripción. Al plazo de ejecución del cargo se aplica lo dispuesto en los artículos 350 y concordantes. Desde que se encuentra expedita, la acción por cumplimiento prescribe según lo establecido en el artículo 2559.", plainLanguageExplanation: "Establece el régimen de tiempo de cumplimiento. Prescripción.", practicalEffects: ['En la práctica, este artículo rige tiempo de cumplimiento. Prescripción.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tiempo', 'cumplimiento', 'articulo 355'], segments: [], amendments: [] },
  { id: 'ccyc-art-356', lawId: 'codigo-civil-comercial', number: '356', order: 356, title: "Transmisibilidad", text: "Transmisibilidad. El derecho adquirido es transmisible por actos entre vivos o por causa de muerte y con él se traspasa la obligación de cumplir el cargo, excepto que sólo pueda ser ejecutado por quien se obligó inicialmente a cumplirlo. Si el cumplimiento del cargo es inherente a la persona y ésta muere sin cumplirlo, la adquisición del derecho principal queda sin efecto, volviendo los bienes al titular originario o a sus herederos. La reversión no afecta a los terceros sino en cuanto pudiese afectarlos la condición resolutoria.", plainLanguageExplanation: "Establece el régimen de transmisibilidad. El derecho adquirido es transmisible por actos entre vivos o por causa de muerte y con él se traspasa la obligación de cumplir el cargo, excepto que sólo pueda ser ejecutado por quien se obligó inicialmente a cumplirlo.", practicalEffects: ['En la práctica, este artículo rige transmisibilidad. El derecho adquirido es transmisible por actos entre vivos o por causa de muerte y con él se traspasa la obligación de cumplir el cargo, excepto que s'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transmisibilidadarticulo 356'], segments: [], amendments: [] },
  { id: 'ccyc-art-357', lawId: 'codigo-civil-comercial', number: '357', order: 357, title: "Cargo prohibido", text: "Cargo prohibido. La estipulación como cargo en los actos jurídicos de hechos que no pueden serlo como condición, se tiene por no escrita, pero no provoca la nulidad del acto. CAPITULO 8 Representación SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de cargo prohibido. La estipulación como cargo en los actos jurídicos de hechos que no pueden serlo como condición, se tiene por no escrita, pero no provoca la nulidad del acto.", practicalEffects: ['En la práctica, este artículo rige cargo prohibido. La estipulación como cargo en los actos jurídicos de hechos que no pueden serlo como condición, se tiene por no escrita, pero no provoca la nulidad del acto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cargo', 'prohibido', 'articulo 357'], segments: [], amendments: [] },
  { id: 'ccyc-art-358', lawId: 'codigo-civil-comercial', number: '358', order: 358, title: "Principio", text: "Principio. Fuentes. Los actos jurídicos entre vivos pueden ser celebrados por medio de representante, excepto en los casos en que la ley exige que sean otorgados por el titular del derecho. La representación es voluntaria cuando resulta de un acto jurídico, es legal cuando resulta de una regla de derecho, y es orgánica cuando resulta del estatuto de una persona jurídica. En las relaciones de familia la representación se rige, en subsidio, por las disposiciones de este Capítulo.", plainLanguageExplanation: "Establece el régimen de principio. Fuentes.", practicalEffects: ['En la práctica, este artículo rige principio. Fuentes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principioarticulo 358'], segments: [], amendments: [] },
  { id: 'ccyc-art-359', lawId: 'codigo-civil-comercial', number: '359', order: 359, title: "Efectos", text: "Efectos. Los actos celebrados por el representante en nombre del representado y en los límites de las facultades conferidas por la ley o por el acto de apoderamiento, producen efecto directamente para el representado.", plainLanguageExplanation: "Establece el régimen de efectos. Los actos celebrados por el representante en nombre del representado y en los límites de las facultades conferidas por la ley o por el acto de apoderamiento, producen efecto directamente para el representado.", practicalEffects: ['En la práctica, este artículo rige efectos. Los actos celebrados por el representante en nombre del representado y en los límites de las facultades conferidas por la ley o por el acto de apodera'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 359'], segments: [], amendments: [] },
  { id: 'ccyc-art-360', lawId: 'codigo-civil-comercial', number: '360', order: 360, title: "Extensión", text: "Extensión. La representación alcanza a los actos objeto del apoderamiento, a las facultades otorgadas por la ley y también a los actos necesarios para su ejecución.", plainLanguageExplanation: "Establece el régimen de extensión. La representación alcanza a los actos objeto del apoderamiento, a las facultades otorgadas por la ley y también a los actos necesarios para su ejecución.", practicalEffects: ['En la práctica, este artículo rige extensión. La representación alcanza a los actos objeto del apoderamiento, a las facultades otorgadas por la ley y también a los actos necesarios para su ejecuci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extensinarticulo 360'], segments: [], amendments: [] },
  { id: 'ccyc-art-361', lawId: 'codigo-civil-comercial', number: '361', order: 361, title: "Limitaciones", text: "Limitaciones. La existencia de supuestos no autorizados y las limitaciones o la extinción del poder son oponibles a terceros si éstos las conocen o pudieron conocerlas actuando con la debida diligencia. SECCION 2ª Representación voluntaria", plainLanguageExplanation: "Establece el régimen de limitaciones. La existencia de supuestos no autorizados y las limitaciones o la extinción del poder son oponibles a terceros si éstos las conocen o pudieron conocerlas actuando con la debida diligencia.", practicalEffects: ['En la práctica, este artículo rige limitaciones. La existencia de supuestos no autorizados y las limitaciones o la extinción del poder son oponibles a terceros si éstos las conocen o pudieron conocerlas actuando con la debida diligencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['limitacionesarticulo 361'], segments: [], amendments: [] },
  { id: 'ccyc-art-362', lawId: 'codigo-civil-comercial', number: '362', order: 362, title: "Caracteres", text: "Caracteres. La representación voluntaria comprende sólo los actos que el representado puede otorgar por sí mismo. Los límites de la representación, su extinción, y las instrucciones que el representado dio a su representante, son oponibles a terceros si éstos han tomado conocimiento de tales circunstancias, o debieron conocerlas obrando con cuidado y previsión.", plainLanguageExplanation: "Establece el régimen de caracteres. La representación voluntaria comprende sólo los actos que el representado puede otorgar por sí mismo.", practicalEffects: ['En la práctica, este artículo rige caracteres. La representación voluntaria comprende sólo los actos que el representado puede otorgar por sí mismo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caracteresarticulo 362'], segments: [], amendments: [] },
  { id: 'ccyc-art-363', lawId: 'codigo-civil-comercial', number: '363', order: 363, title: "Forma", text: "Forma. El apoderamiento debe ser otorgado en la forma prescripta para el acto que el representante debe realizar.", plainLanguageExplanation: "Establece el régimen de forma. El apoderamiento debe ser otorgado en la forma prescripta para el acto que el representante debe realizar.", practicalEffects: ['En la práctica, este artículo rige forma. El apoderamiento debe ser otorgado en la forma prescripta para el acto que el representante debe realizar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 363'], segments: [], amendments: [] },
  { id: 'ccyc-art-364', lawId: 'codigo-civil-comercial', number: '364', order: 364, title: "Capacidad", text: "Capacidad. En la representación voluntaria el representado debe tener capacidad para otorgar el acto al momento del apoderamiento; para el representante es suficiente el discernimiento.", plainLanguageExplanation: "Establece el régimen de capacidad. En la representación voluntaria el representado debe tener capacidad para otorgar el acto al momento del apoderamiento; para el representante es suficiente el discernimiento.", practicalEffects: ['En la práctica, este artículo rige capacidad. En la representación voluntaria el representado debe tener capacidad para otorgar el acto al momento del apoderamiento; para el representante es sufic'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capacidadarticulo 364'], segments: [], amendments: [] },
  { id: 'ccyc-art-365', lawId: 'codigo-civil-comercial', number: '365', order: 365, title: "Vicios", text: "Vicios. El acto otorgado por el representante es nulo si su voluntad está viciada. Pero si se ha otorgado en ejercicio de facultades previamente determinadas por el representado es nulo sólo si estuvo viciada la voluntad de éste. El representado de mala fe no puede aprovecharse de la ignorancia o la buena fe del representante.", plainLanguageExplanation: "Establece el régimen de vicios. El acto otorgado por el representante es nulo si su voluntad está viciada.", practicalEffects: ['En la práctica, este artículo rige vicios. El acto otorgado por el representante es nulo si su voluntad está viciada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['viciosarticulo 365'], segments: [], amendments: [] },
  { id: 'ccyc-art-366', lawId: 'codigo-civil-comercial', number: '366', order: 366, title: "Actuación en ejercicio del poder", text: "Actuación en ejercicio del poder. Cuando un representante actúa dentro del marco de su poder, sus actos obligan directamente al representado y a los terceros. El representante no queda obligado para con los terceros, excepto que haya garantizado de algún modo el negocio. Si la voluntad de obrar en nombre de otro no aparece claramente, se entiende que ha procedido en nombre propio.", plainLanguageExplanation: "Establece el régimen de actuación en ejercicio del poder. Cuando un representante actúa dentro del marco de su poder, sus actos obligan directamente al representado y a los terceros.", practicalEffects: ['En la práctica, este artículo rige actuación en ejercicio del poder. Cuando un representante actúa dentro del marco de su poder, sus actos obligan directamente al representado y a los terceros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actuacin', 'ejercicio', 'poder', 'articulo 366'], segments: [], amendments: [] },
  { id: 'ccyc-art-367', lawId: 'codigo-civil-comercial', number: '367', order: 367, title: "Representación aparente", text: "Representación aparente. Cuando alguien ha obrado de manera de inducir a un tercero a celebrar un acto jurídico, dejándolo creer razonablemente que negocia con su representante, sin que haya representación expresa, se entiende que le ha otorgado tácitamente poder suficiente. A tal efecto se presume que: a) quien de manera notoria tiene la administración de un establecimiento abierto al público es apoderado para todos los actos propios de la gestión ordinaria de éste; b) los dependientes que se desempeñan en el establecimiento están facultados para todos los actos que ordinariamente corresponden a las funciones que realizan; c) los dependientes encargados de entregar mercaderías fuera del establecimiento están facultados a percibir su precio otorgando el pertinente recibo.", plainLanguageExplanation: "Establece el régimen de representación aparente. Cuando alguien ha obrado de manera de inducir a un tercero a celebrar un acto jurídico, dejándolo creer razonablemente que negocia con su representante, sin que haya representación expresa, se entiende que le ha otorgado tácitamente poder suficiente.", practicalEffects: ['En la práctica, este artículo rige representación aparente. Cuando alguien ha obrado de manera de inducir a un tercero a celebrar un acto jurídico, dejándolo creer razonablemente que negocia con su representant'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representacin', 'aparente', 'articulo 367'], segments: [], amendments: [] },
  { id: 'ccyc-art-368', lawId: 'codigo-civil-comercial', number: '368', order: 368, title: "Acto consigo mismo", text: "Acto consigo mismo. Nadie puede, en representación de otro, efectuar consigo mismo un acto jurídico, sea por cuenta propia o de un tercero, sin la autorización del representado. Tampoco puede el representante, sin la conformidad del representado, aplicar fondos o rentas obtenidos en ejercicio de la representación a sus propios negocios, o a los ajenos confiados a su gestión.", plainLanguageExplanation: "Establece el régimen de acto consigo mismo. Nadie puede, en representación de otro, efectuar consigo mismo un acto jurídico, sea por cuenta propia o de un tercero, sin la autorización del representado.", practicalEffects: ['En la práctica, este artículo rige acto consigo mismo. Nadie puede, en representación de otro, efectuar consigo mismo un acto jurídico, sea por cuenta propia o de un tercero, sin la autorización del representado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acto', 'consigo', 'mismo', 'articulo 368'], segments: [], amendments: [] },
  { id: 'ccyc-art-369', lawId: 'codigo-civil-comercial', number: '369', order: 369, title: "Ratificación", text: "Ratificación. La ratificación suple el defecto de representación. Luego de la ratificación, la actuación se da por autorizada, con efecto retroactivo al día del acto, pero es inoponible a terceros que hayan adquirido derechos con anterioridad.", plainLanguageExplanation: "Establece el régimen de ratificación. La ratificación suple el defecto de representación.", practicalEffects: ['En la práctica, este artículo rige ratificación. La ratificación suple el defecto de representación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ratificacinarticulo 369'], segments: [], amendments: [] },
  { id: 'ccyc-art-370', lawId: 'codigo-civil-comercial', number: '370', order: 370, title: "Tiempo de la ratificación", text: "Tiempo de la ratificación. La ratificación puede hacerse en cualquier tiempo, pero los interesados pueden requerirla, fijando un plazo para ello que no puede exceder de quince días; el silencio se debe interpretar como negativa. Si la ratificación depende de la autoridad administrativa o judicial, el término se extiende a tres meses. El tercero que no haya requerido la ratificación puede revocar su consentimiento sin esperar el vencimiento de estos términos.", plainLanguageExplanation: "Establece el régimen de tiempo de la ratificación. La ratificación puede hacerse en cualquier tiempo, pero los interesados pueden requerirla, fijando un plazo para ello que no puede exceder de quince días; el silencio se debe interpretar como negativa.", practicalEffects: ['En la práctica, este artículo rige tiempo de la ratificación. La ratificación puede hacerse en cualquier tiempo, pero los interesados pueden requerirla, fijando un plazo para ello que no puede exceder de quince d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tiempo', 'ratificacin', 'articulo 370'], segments: [], amendments: [] },
  { id: 'ccyc-art-371', lawId: 'codigo-civil-comercial', number: '371', order: 371, title: "Manifestación de la ratificación", text: "Manifestación de la ratificación. La ratificación resulta de cualquier manifestación expresa o de cualquier acto o comportamiento concluyente que necesariamente importe una aprobación de lo que haya hecho el que invoca la representación.", plainLanguageExplanation: "Establece el régimen de manifestación de la ratificación. La ratificación resulta de cualquier manifestación expresa o de cualquier acto o comportamiento concluyente que necesariamente importe una aprobación de lo que haya hecho el que invoca la representación.", practicalEffects: ['En la práctica, este artículo rige manifestación de la ratificación. La ratificación resulta de cualquier manifestación expresa o de cualquier acto o comportamiento concluyente que necesariamente importe una aprobación'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['manifestacin', 'ratificacin', 'articulo 371'], segments: [], amendments: [] },
  { id: 'ccyc-art-372', lawId: 'codigo-civil-comercial', number: '372', order: 372, title: "Obligaciones y deberes del representante", text: "Obligaciones y deberes del representante. El representante tiene las siguientes obligaciones y deberes: a) de fidelidad, lealtad y reserva; b) de realización de la gestión encomendada, que exige la legalidad de su prestación, el cumplimiento de las instrucciones del representado, y el desarrollo de una conducta según los usos y prácticas del tráfico; c) de comunicación, que incluye los de información y de consulta; d) de conservación y de custodia; e) de prohibición, como regla, de adquirir por compraventa o actos jurídicos análogos los bienes de su representado; f) de restitución de documentos y demás bienes que le correspondan al representado al concluirse la gestión.", plainLanguageExplanation: "Establece el régimen de obligaciones y deberes del representante. El representante tiene las siguientes obligaciones y deberes: a) de fidelidad, lealtad y reserva; b) de realización de la gestión encomendada, que exige la legalidad de su prestación, el cumplimiento de las instrucciones del representado, y el desarrollo de una conducta según los", practicalEffects: ['En la práctica, este artículo rige obligaciones y deberes del representante. El representante tiene las siguientes obligaciones y deberes: a) de fidelidad, lealtad y reserva; b) de realización de la gestión encomendada, que exi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'deberes', 'representante', 'articulo 372'], segments: [], amendments: [] },
  { id: 'ccyc-art-373', lawId: 'codigo-civil-comercial', number: '373', order: 373, title: "Obligaciones y deberes del representado", text: "Obligaciones y deberes del representado. El representado tiene las siguientes obligaciones y deberes: a) de prestar los medios necesarios para el cumplimiento de la gestión; b) de retribuir la gestión, si corresponde; c) de dejar indemne al representante.", plainLanguageExplanation: "Establece el régimen de obligaciones y deberes del representado. El representado tiene las siguientes obligaciones y deberes: a) de prestar los medios necesarios para el cumplimiento de la gestión; b) de retribuir la gestión, si corresponde; c) de dejar indemne al representante.", practicalEffects: ['En la práctica, este artículo rige obligaciones y deberes del representado. El representado tiene las siguientes obligaciones y deberes: a) de prestar los medios necesarios para el cumplimiento de la gestión; b) de retribuir l'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'deberes', 'representado', 'articulo 373'], segments: [], amendments: [] },
  { id: 'ccyc-art-374', lawId: 'codigo-civil-comercial', number: '374', order: 374, title: "Copia", text: "Copia. Los terceros pueden exigir que el representante suscriba y les entregue copia firmada por él del instrumento del que resulta su representación.", plainLanguageExplanation: "Establece el régimen de copia. Los terceros pueden exigir que el representante suscriba y les entregue copia firmada por él del instrumento del que resulta su representación.", practicalEffects: ['En la práctica, este artículo rige copia. Los terceros pueden exigir que el representante suscriba y les entregue copia firmada por él del instrumento del que resulta su representación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['copiaarticulo 374'], segments: [], amendments: [] },
  { id: 'ccyc-art-375', lawId: 'codigo-civil-comercial', number: '375', order: 375, title: "Poder conferido en términos generales y facultades expresas", text: "Poder conferido en términos generales y facultades expresas. Las facultades contenidas en el poder son de interpretación restrictiva. El poder conferido en términos generales sólo incluye los actos propios de administración ordinaria y los necesarios para su ejecución. Son necesarias facultades expresas para: a) peticionar el divorcio, la nulidad de matrimonio, la modificación, disolución o liquidación del régimen patrimonial del matrimonio; b) otorgar el asentimiento conyugal si el acto lo requiere, caso en el que deben identificarse los bienes a que se refiere; c) reconocer hijos, caso en el que debe individualizarse a la persona que se reconoce; d) aceptar herencias; e) constituir, modificar, transferir o extinguir derechos reales sobre inmuebles u otros bienes registrables; f) crear obligaciones por una declaración unilateral de voluntad; g) reconocer o novar obligaciones anteriores al otorgamiento del poder; h) hacer pagos que no sean los ordinarios de la administración; i) renunciar, transar, someter a juicio arbitral derechos u obligaciones, sin perjuicio de las reglas aplicables en materia de concursos y quiebras; j) formar uniones transitorias de empresas, agrupamientos de colaboración empresaria, sociedades, asociaciones, o fundaciones; k) dar o tomar en locación inmuebles por más de tres años, o cobrar alquileres anticipados por más de un año; l) realizar donaciones, u otras liberalidades, excepto pequeñas gratificaciones habituales; m) dar fianzas, comprometer servicios personales, recibir cosas en depósito si no se trata del necesario, y dar o tomar dinero en préstamo, excepto cuando estos actos correspondan al objeto para el que se otorgó un poder en términos generales.", plainLanguageExplanation: "Establece el régimen de poder conferido en términos generales y facultades expresas. Las facultades contenidas en el poder son de interpretación restrictiva.", practicalEffects: ['En la práctica, este artículo rige poder conferido en términos generales y facultades expresas. Las facultades contenidas en el poder son de interpretación restrictiva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['poder', 'conferido', 'trminos', 'generales', 'facultades', 'expresas', 'articulo 375'], segments: [], amendments: [] },
  { id: 'ccyc-art-376', lawId: 'codigo-civil-comercial', number: '376', order: 376, title: "Responsabilidad por inexistencia o exceso en la representación", text: "Responsabilidad por inexistencia o exceso en la representación. Si alguien actúa como representante de otro sin serlo, o en exceso de las facultades conferidas por el representado, es responsable del daño que la otra parte sufra por haber confiado, sin culpa suya, en la validez del acto; si hace saber al tercero la falta o deficiencia de su poder, está exento de dicha responsabilidad.", plainLanguageExplanation: "Establece el régimen de responsabilidad por inexistencia o exceso en la representación. Si alguien actúa como representante de otro sin serlo, o en exceso de las facultades conferidas por el representado, es responsable del daño que la otra parte sufra por haber confiado, sin culpa suya, en la validez del acto; si hace saber al tercero la falta o deficiencia de su p", practicalEffects: ['En la práctica, este artículo rige responsabilidad por inexistencia o exceso en la representación. Si alguien actúa como representante de otro sin serlo, o en exceso de las facultades conferidas por el representado, es responsable del daño que la ot'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'inexistencia', 'exceso', 'representacin', 'articulo 376'], segments: [], amendments: [] },
  { id: 'ccyc-art-377', lawId: 'codigo-civil-comercial', number: '377', order: 377, title: "Sustitución", text: "Sustitución. El representante puede sustituir el poder en otro. Responde por el sustituto si incurre en culpa al elegir. El representado puede indicar la persona del sustituto, caso en el cual el representante no responde por éste. El representado puede prohibir la sustitución.", plainLanguageExplanation: "Establece el régimen de sustitución. El representante puede sustituir el poder en otro.", practicalEffects: ['En la práctica, este artículo rige sustitución. El representante puede sustituir el poder en otro.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sustitucinarticulo 377'], segments: [], amendments: [] },
  { id: 'ccyc-art-378', lawId: 'codigo-civil-comercial', number: '378', order: 378, title: "Pluralidad de representantes", text: "Pluralidad de representantes. La designación de varios representantes, sin indicación de que deban actuar conjuntamente, todos o algunos de ellos, se entiende que faculta a actuar indistintamente a cualquiera de ellos.", plainLanguageExplanation: "Establece el régimen de pluralidad de representantes. La designación de varios representantes, sin indicación de que deban actuar conjuntamente, todos o algunos de ellos, se entiende que faculta a actuar indistintamente a cualquiera de ellos.", practicalEffects: ['En la práctica, este artículo rige pluralidad de representantes. La designación de varios representantes, sin indicación de que deban actuar conjuntamente, todos o algunos de ellos, se entiende que faculta a actuar'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pluralidad', 'representantes', 'articulo 378'], segments: [], amendments: [] },
  { id: 'ccyc-art-379', lawId: 'codigo-civil-comercial', number: '379', order: 379, title: "Apoderamiento plural", text: "Apoderamiento plural. El poder otorgado por varias personas para un objeto de interés común puede ser revocado por cualquiera de ellas sin dependencia de las otras.", plainLanguageExplanation: "Establece el régimen de apoderamiento plural. El poder otorgado por varias personas para un objeto de interés común puede ser revocado por cualquiera de ellas sin dependencia de las otras.", practicalEffects: ['En la práctica, este artículo rige apoderamiento plural. El poder otorgado por varias personas para un objeto de interés común puede ser revocado por cualquiera de ellas sin dependencia de las otras.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['apoderamiento', 'plural', 'articulo 379'], segments: [], amendments: [] },
  { id: 'ccyc-art-380', lawId: 'codigo-civil-comercial', number: '380', order: 380, title: "Extinción", text: "Extinción. El poder se extingue: a) por el cumplimiento del o de los actos encomendados en el apoderamiento; b) por la muerte del representante o del representado; sin embargo subsiste en caso de muerte del representado siempre que haya sido conferido para actos especialmente determinados y en razón de un interés legítimo que puede ser solamente del representante, de un tercero o común a representante y representado, o a representante y un tercero, o a representado y tercero; c) por la revocación efectuada por el representado; sin embargo, un poder puede ser conferido de modo irrevocable, siempre que lo sea para actos especialmente determinados, limitado por un plazo cierto, y en razón de un interés legítimo que puede ser solamente del representante, o de un tercero, o común a representante y representado, o a representante y un tercero, o a representado y tercero; se extingue llegado el transcurso del plazo fijado y puede revocarse si media justa causa; d) por la renuncia del representante, pero éste debe continuar en funciones hasta que notifique aquélla al representado, quien puede actuar por sí o reemplazarlo, excepto que acredite un impedimento que configure justa causa; e) por la declaración de muerte presunta del representante o del representado; f) por la declaración de ausencia del representante; g) por la quiebra del representante o representado; h) por la pérdida de la capacidad exigida en el representante o en el representado.", plainLanguageExplanation: "Establece el régimen de extinción. El poder se extingue: a) por el cumplimiento del o de los actos encomendados en el apoderamiento; b) por la muerte del representante o del representado; sin embargo subsiste en caso de muerte del representado siempre que haya sido conferido para actos especialmente determinados y", practicalEffects: ['En la práctica, este artículo rige extinción. El poder se extingue: a) por el cumplimiento del o de los actos encomendados en el apoderamiento; b) por la muerte del representante o del representad'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincinarticulo 380'], segments: [], amendments: [] },
  { id: 'ccyc-art-381', lawId: 'codigo-civil-comercial', number: '381', order: 381, title: "Oponibilidad a terceros", text: "Oponibilidad a terceros. Las modificaciones, la renuncia y la revocación de los poderes deben ser puestas en conocimiento de los terceros por medios idóneos. En su defecto, no son oponibles a los terceros, a menos que se pruebe que éstos conocían las modificaciones o la revocación en el momento de celebrar el acto jurídico. Las demás causas de extinción del poder no son oponibles a los terceros que las hayan ignorado sin su culpa. CAPITULO 9 Ineficacia de los actos jurídicos SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de oponibilidad a terceros. Las modificaciones, la renuncia y la revocación de los poderes deben ser puestas en conocimiento de los terceros por medios idóneos.", practicalEffects: ['En la práctica, este artículo rige oponibilidad a terceros. Las modificaciones, la renuncia y la revocación de los poderes deben ser puestas en conocimiento de los terceros por medios idóneos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oponibilidad', 'terceros', 'articulo 381'], segments: [], amendments: [] },
  { id: 'ccyc-art-382', lawId: 'codigo-civil-comercial', number: '382', order: 382, title: "Categorías de ineficacia", text: "Categorías de ineficacia. Los actos jurídicos pueden ser ineficaces en razón de su nulidad o de su inoponibilidad respecto de determinadas personas.", plainLanguageExplanation: "Establece el régimen de categorías de ineficacia. Los actos jurídicos pueden ser ineficaces en razón de su nulidad o de su inoponibilidad respecto de determinadas personas.", practicalEffects: ['En la práctica, este artículo rige categorías de ineficacia. Los actos jurídicos pueden ser ineficaces en razón de su nulidad o de su inoponibilidad respecto de determinadas personas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['categoras', 'ineficacia', 'articulo 382'], segments: [], amendments: [] },
  { id: 'ccyc-art-383', lawId: 'codigo-civil-comercial', number: '383', order: 383, title: "Articulación", text: "Articulación. La nulidad puede argüirse por vía de acción u oponerse como excepción. En todos los casos debe sustanciarse.", plainLanguageExplanation: "Establece el régimen de articulación. La nulidad puede argüirse por vía de acción u oponerse como excepción.", practicalEffects: ['En la práctica, este artículo rige articulación. La nulidad puede argüirse por vía de acción u oponerse como excepción.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['articulacinarticulo 383'], segments: [], amendments: [] },
  { id: 'ccyc-art-384', lawId: 'codigo-civil-comercial', number: '384', order: 384, title: "Conversión", text: "Conversión. El acto nulo puede convertirse en otro diferente válido cuyos requisitos esenciales satisfaga, si el fin práctico perseguido por las partes permite suponer que ellas lo habrían querido si hubiesen previsto la nulidad.", plainLanguageExplanation: "Establece el régimen de conversión. El acto nulo puede convertirse en otro diferente válido cuyos requisitos esenciales satisfaga, si el fin práctico perseguido por las partes permite suponer que ellas lo habrían querido si hubiesen previsto la nulidad.", practicalEffects: ['En la práctica, este artículo rige conversión. El acto nulo puede convertirse en otro diferente válido cuyos requisitos esenciales satisfaga, si el fin práctico perseguido por las partes permite su'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conversinarticulo 384'], segments: [], amendments: [] },
  { id: 'ccyc-art-385', lawId: 'codigo-civil-comercial', number: '385', order: 385, title: "Acto indirecto", text: "Acto indirecto. Un acto jurídico celebrado para obtener un resultado que es propio de los efectos de otro acto, es válido si no se otorga para eludir una prohibición de la ley o para perjudicar a un tercero. SECCION 2ª Nulidad absoluta y relativa", plainLanguageExplanation: "Establece el régimen de acto indirecto. Un acto jurídico celebrado para obtener un resultado que es propio de los efectos de otro acto, es válido si no se otorga para eludir una prohibición de la ley o para perjudicar a un tercero.", practicalEffects: ['En la práctica, este artículo rige acto indirecto. Un acto jurídico celebrado para obtener un resultado que es propio de los efectos de otro acto, es válido si no se otorga para eludir una prohibición de la ley o para perjudicar a un tercero.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acto', 'indirecto', 'articulo 385'], segments: [], amendments: [] },
  { id: 'ccyc-art-386', lawId: 'codigo-civil-comercial', number: '386', order: 386, title: "Criterio de distinción", text: "Criterio de distinción. Son de nulidad absoluta los actos que contravienen el orden público, la moral o las buenas costumbres. Son de nulidad relativa los actos a los cuales la ley impone esta sanción sólo en protección del interés de ciertas personas.", plainLanguageExplanation: "Establece el régimen de criterio de distinción. Son de nulidad absoluta los actos que contravienen el orden público, la moral o las buenas costumbres.", practicalEffects: ['En la práctica, este artículo rige criterio de distinción. Son de nulidad absoluta los actos que contravienen el orden público, la moral o las buenas costumbres.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['criterio', 'distincin', 'articulo 386'], segments: [], amendments: [] },
  { id: 'ccyc-art-387', lawId: 'codigo-civil-comercial', number: '387', order: 387, title: "Nulidad absoluta", text: "Nulidad absoluta. Consecuencias. La nulidad absoluta puede declararse por el juez, aun sin mediar petición de parte, si es manifiesta en el momento de dictar sentencia. Puede alegarse por el Ministerio Público y por cualquier interesado, excepto por la parte que invoque la propia torpeza para lograr un provecho. No puede sanearse por la confirmación del acto ni por la prescripción.", plainLanguageExplanation: "Establece el régimen de nulidad absoluta. Consecuencias.", practicalEffects: ['En la práctica, este artículo rige nulidad absoluta. Consecuencias.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidad', 'absoluta', 'articulo 387'], segments: [], amendments: [] },
  { id: 'ccyc-art-388', lawId: 'codigo-civil-comercial', number: '388', order: 388, title: "Nulidad relativa", text: "Nulidad relativa. Consecuencias. La nulidad relativa sólo puede declararse a instancia de las personas en cuyo beneficio se establece. Excepcionalmente puede invocarla la otra parte, si es de buena fe y ha experimentado un perjuicio importante. Puede sanearse por la confirmación del acto y por la prescripción de la acción. La parte que obró con ausencia de capacidad de ejercicio para el acto, no puede alegarla si obró con dolo. SECCION 3ª Nulidad total y parcial", plainLanguageExplanation: "Establece el régimen de nulidad relativa. Consecuencias.", practicalEffects: ['En la práctica, este artículo rige nulidad relativa. Consecuencias.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidad', 'relativa', 'articulo 388'], segments: [], amendments: [] },
  { id: 'ccyc-art-389', lawId: 'codigo-civil-comercial', number: '389', order: 389, title: "Principio", text: "Principio. Integración. Nulidad total es la que se extiende a todo el acto. Nulidad parcial es la que afecta a una o varias de sus disposiciones. La nulidad de una disposición no afecta a las otras disposiciones válidas, si son separables. Si no son separables porque el acto no puede subsistir sin cumplir su finalidad, se declara la nulidad total. En la nulidad parcial, en caso de ser necesario, el juez debe integrar el acto de acuerdo a su naturaleza y los intereses que razonablemente puedan considerarse perseguidos por las partes. SECCION 4ª Efectos de la nulidad", plainLanguageExplanation: "Establece el régimen de principio. Integración.", practicalEffects: ['En la práctica, este artículo rige principio. Integración.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principioarticulo 389'], segments: [], amendments: [] },
  { id: 'ccyc-art-390', lawId: 'codigo-civil-comercial', number: '390', order: 390, title: "Restitución", text: "Restitución. La nulidad pronunciada por los jueces vuelve las cosas al mismo estado en que se hallaban antes del acto declarado nulo y obliga a las partes a restituirse mutuamente lo que han recibido. Estas restituciones se rigen por las disposiciones relativas a la buena o mala fe según sea el caso, de acuerdo a lo dispuesto en las normas del Capítulo 3 del Título II del Libro Cuarto.", plainLanguageExplanation: "Establece el régimen de restitución. La nulidad pronunciada por los jueces vuelve las cosas al mismo estado en que se hallaban antes del acto declarado nulo y obliga a las partes a restituirse mutuamente lo que han recibido.", practicalEffects: ['En la práctica, este artículo rige restitución. La nulidad pronunciada por los jueces vuelve las cosas al mismo estado en que se hallaban antes del acto declarado nulo y obliga a las partes a restituirse mutuamente lo que han recibido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['restitucinarticulo 390'], segments: [], amendments: [] },
  { id: 'ccyc-art-391', lawId: 'codigo-civil-comercial', number: '391', order: 391, title: "Hechos simples", text: "Hechos simples. Los actos jurídicos nulos, aunque no produzcan los efectos de los actos válidos, dan lugar en su caso a las consecuencias de los hechos en general y a las reparaciones que correspondan.", plainLanguageExplanation: "Establece el régimen de hechos simples. Los actos jurídicos nulos, aunque no produzcan los efectos de los actos válidos, dan lugar en su caso a las consecuencias de los hechos en general y a las reparaciones que correspondan.", practicalEffects: ['En la práctica, este artículo rige hechos simples. Los actos jurídicos nulos, aunque no produzcan los efectos de los actos válidos, dan lugar en su caso a las consecuencias de los hechos en general y a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hechos', 'simples', 'articulo 391'], segments: [], amendments: [] },
  { id: 'ccyc-art-392', lawId: 'codigo-civil-comercial', number: '392', order: 392, title: "Efectos respecto de terceros en cosas registrables", text: "Efectos respecto de terceros en cosas registrables. Todos los derechos reales o personales transmitidos a terceros sobre un inmueble o mueble registrable, por una persona que ha resultado adquirente en virtud de un acto nulo, quedan sin ningún valor, y pueden ser reclamados directamente del tercero, excepto contra el subadquirente de derechos reales o personales de buena fe y a título oneroso. Los subadquirentes no pueden ampararse en su buena fe y título oneroso si el acto se ha realizado sin intervención del titular del derecho. SECCION 5ª Confirmación", plainLanguageExplanation: "Establece el régimen de efectos respecto de terceros en cosas registrables. Todos los derechos reales o personales transmitidos a terceros sobre un inmueble o mueble registrable, por una persona que ha resultado adquirente en virtud de un acto nulo, quedan sin ningún valor, y pueden ser reclamados directamente del tercero, excepto contra el subadquirente", practicalEffects: ['En la práctica, este artículo rige efectos respecto de terceros en cosas registrables. Todos los derechos reales o personales transmitidos a terceros sobre un inmueble o mueble registrable, por una persona que ha resultado adquirente en'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'respecto', 'terceros', 'cosas', 'registrables', 'articulo 392'], segments: [], amendments: [] },
  { id: 'ccyc-art-393', lawId: 'codigo-civil-comercial', number: '393', order: 393, title: "Requisitos", text: "Requisitos. Hay confirmación cuando la parte que puede articular la nulidad relativa manifiesta expresa o tácitamente su voluntad de tener al acto por válido, después de haber desaparecido la causa de nulidad. El acto de confirmación no requiere la conformidad de la otra parte.", plainLanguageExplanation: "Establece el régimen de requisitos. Hay confirmación cuando la parte que puede articular la nulidad relativa manifiesta expresa o tácitamente su voluntad de tener al acto por válido, después de haber desaparecido la causa de nulidad.", practicalEffects: ['En la práctica, este artículo rige requisitos. Hay confirmación cuando la parte que puede articular la nulidad relativa manifiesta expresa o tácitamente su voluntad de tener al acto por válido, después de haber desaparecido la causa de nulidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 393'], segments: [], amendments: [] },
  { id: 'ccyc-art-394', lawId: 'codigo-civil-comercial', number: '394', order: 394, title: "Forma", text: "Forma. Si la confirmación es expresa, el instrumento en que ella conste debe reunir las formas exigidas para el acto que se sanea y contener la mención precisa de la causa de la nulidad, de su desaparición y de la voluntad de confirmar el acto. La confirmación tácita resulta del cumplimiento total o parcial del acto nulo realizado con conocimiento de la causa de nulidad o de otro acto del que se deriva la voluntad inequívoca de sanear el vicio del acto.", plainLanguageExplanation: "Establece el régimen de forma. Si la confirmación es expresa, el instrumento en que ella conste debe reunir las formas exigidas para el acto que se sanea y contener la mención precisa de la causa de la nulidad, de su desaparición y de la voluntad de confirmar el acto.", practicalEffects: ['En la práctica, este artículo rige forma. Si la confirmación es expresa, el instrumento en que ella conste debe reunir las formas exigidas para el acto que se sanea y contener la mención preci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 394'], segments: [], amendments: [] },
  { id: 'ccyc-art-395', lawId: 'codigo-civil-comercial', number: '395', order: 395, title: "Efecto retroactivo", text: "Efecto retroactivo. La confirmación del acto entre vivos originalmente nulo tiene efecto retroactivo a la fecha en que se celebró. La confirmación de disposiciones de última voluntad opera desde la muerte del causante. La retroactividad de la confirmación no perjudica los derechos de terceros de buena fe. SECCION 6ª Inoponibilidad", plainLanguageExplanation: "Establece el régimen de efecto retroactivo. La confirmación del acto entre vivos originalmente nulo tiene efecto retroactivo a la fecha en que se celebró.", practicalEffects: ['En la práctica, este artículo rige efecto retroactivo. La confirmación del acto entre vivos originalmente nulo tiene efecto retroactivo a la fecha en que se celebró.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efecto', 'retroactivo', 'articulo 395'], segments: [], amendments: [] },
  { id: 'ccyc-art-396', lawId: 'codigo-civil-comercial', number: '396', order: 396, title: "Efectos del acto inoponible frente a terceros", text: "Efectos del acto inoponible frente a terceros. El acto inoponible no tiene efectos con respecto a terceros, excepto en los casos previstos por la ley.", plainLanguageExplanation: "Establece el régimen de efectos del acto inoponible frente a terceros. El acto inoponible no tiene efectos con respecto a terceros, excepto en los casos previstos por la ley.", practicalEffects: ['En la práctica, este artículo rige efectos del acto inoponible frente a terceros. El acto inoponible no tiene efectos con respecto a terceros, excepto en los casos previstos por la ley.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'acto', 'inoponible', 'frente', 'terceros', 'articulo 396'], segments: [], amendments: [] },
  { id: 'ccyc-art-397', lawId: 'codigo-civil-comercial', number: '397', order: 397, title: "Oportunidad para invocarla", text: "Oportunidad para invocarla. La inoponibilidad puede hacerse valer en cualquier momento, sin perjuicio del derecho de la otra parte a oponer la prescripción o la caducidad. TITULO V Transmisión de los derechos", plainLanguageExplanation: "Establece el régimen de oportunidad para invocarla. La inoponibilidad puede hacerse valer en cualquier momento, sin perjuicio del derecho de la otra parte a oponer la prescripción o la caducidad.", practicalEffects: ['En la práctica, este artículo rige oportunidad para invocarla. La inoponibilidad puede hacerse valer en cualquier momento, sin perjuicio del derecho de la otra parte a oponer la prescripción o la caducidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oportunidad', 'para', 'invocarla', 'articulo 397'], segments: [], amendments: [] },
  { id: 'ccyc-art-398', lawId: 'codigo-civil-comercial', number: '398', order: 398, title: "Transmisibilidad", text: "Transmisibilidad. Todos los derechos son transmisibles excepto estipulación válida de las partes o que ello resulte de una prohibición legal o que importe trasgresión a la buena fe, a la moral o a las buenas costumbres.", plainLanguageExplanation: "Establece el régimen de transmisibilidad. Todos los derechos son transmisibles excepto estipulación válida de las partes o que ello resulte de una prohibición legal o que importe trasgresión a la buena fe, a la moral o a las buenas costumbres.", practicalEffects: ['En la práctica, este artículo rige transmisibilidad. Todos los derechos son transmisibles excepto estipulación válida de las partes o que ello resulte de una prohibición legal o que importe trasgresión a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transmisibilidadarticulo 398'], segments: [], amendments: [] },
  { id: 'ccyc-art-399', lawId: 'codigo-civil-comercial', number: '399', order: 399, title: "Regla general", text: "Regla general. Nadie puede transmitir a otro un derecho mejor o más extenso que el que tiene, sin perjuicio de las excepciones legalmente dispuestas.", plainLanguageExplanation: "Establece el régimen de regla general. Nadie puede transmitir a otro un derecho mejor o más extenso que el que tiene, sin perjuicio de las excepciones legalmente dispuestas.", practicalEffects: ['En la práctica, este artículo rige regla general. Nadie puede transmitir a otro un derecho mejor o más extenso que el que tiene, sin perjuicio de las excepciones legalmente dispuestas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['regla', 'general', 'articulo 399'], segments: [], amendments: [] },
  { id: 'ccyc-art-400', lawId: 'codigo-civil-comercial', number: '400', order: 400, title: "Sucesores", text: "Sucesores. Sucesor universal es el que recibe todo o una parte indivisa del patrimonio de otro; sucesor singular el que recibe un derecho en particular. LIBRO SEGUNDO RELACIONES DE FAMILIA TITULO I Matrimonio CAPITULO 1 Principios de libertad y de igualdad", plainLanguageExplanation: "Establece el régimen de sucesores. Sucesor universal es el que recibe todo o una parte indivisa del patrimonio de otro; sucesor singular el que recibe un derecho en particular.", practicalEffects: ['En la práctica, este artículo rige sucesores. Sucesor universal es el que recibe todo o una parte indivisa del patrimonio de otro; sucesor singular el que recibe un derecho en particular.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sucesoresarticulo 400'], segments: [], amendments: [] },
];
